MultiLanguageSpellData['es'][465999] = {name = "Rugidor acorazado carmesí", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Algunos goblins se refieren cariñosamente a sus hienas adiestradas como \"gruñidoras\". A esta lo que le gusta es cavar.\"\nVendedor:\nRocco Bombaburla\nZona:\nMinahonda\nCoste:\n8125"}
MultiLanguageSpellData['es'][466000] = {name = "Zampador de Fundisombras", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Considerado el mandamás de las hienas de desguace de Stix. Tiene suficiente potencia en las fauces como para aplastar cualquier cosa o persona de las que Gallywix quiera deshacerse.\"\nVendedor:\n\"Revólver\" Ando\nZona:\nLiberación de Minahonda\nCoste:\n500"}
MultiLanguageSpellData['es'][466001] = {name = "Aplastahuesos de Aguasnegras", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Cuida bien esos huesos si no quieres que te los aplasten.\"\nBotín:\nTesoro de Aguasnegras\nZona:\nMinahonda"}
MultiLanguageSpellData['es'][466002] = {name = "Rugidor acorazado violeta", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Smaks sabe un par de cosas sobre el cuidado de las hienas. Regla número uno: ¡ni se te ocurra acercar las manos a esos dientes!\"\nVendedor:\nSmaks Suprarrayador\nZona:\nMinahonda\nCoste:\n8125"}
MultiLanguageSpellData['es'][466006] = {name = "Gran montón de basura", additional_info = nil}
MultiLanguageSpellData['es'][466007] = {name = "Cangrejobús", additional_info = "Instante\n[q]Las bombas reptadoras tienen un revestimiento protector resistente que reduce un 99% todo el daño recibido.\n\n Solo explotan al entrar en contacto con su objetivo y entonces infligen 300 p. de daño de Fuego a los jugadores en un radio de 5 m."}
MultiLanguageSpellData['es'][466011] = {name = "Flarendo el Furioso", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Ser el VIP de los VIP de El Gallagio tiene sus ventajas, como las llaves de este antiguo Rey de la carnicería. ¡Su tecnología goblin de vanguardia hace que consuma un litro de gasolina por cada 100 m!\"\nVendedor:\n\"Revólver\" Ando\nZona:\nLiberación de Minahonda\nCoste:\n777"}
MultiLanguageSpellData['es'][466012] = {name = "Casquillo de tambor atronador", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Recuperado de las gradas de la Caldera durante un enfrentamiento especialmente espantoso. Cuando le preguntaron si era defectuoso, el operador de Torq solo respondió: \"Probablemente\".\"\nVendedor:\n\"Revólver\" Ando\nZona:\nLiberación de Minahonda\nCoste:\n500"}
MultiLanguageSpellData['es'][466013] = {name = "Cohete para envíos ocre", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"¡Lleva paquetes y pasajeros del punto A al B con estilo!\"\nVendedor:\nShredz el Desguazador\nZona:\nMinahonda\nCoste:\n11375"}
MultiLanguageSpellData['es'][466014] = {name = "Suministrador de Bonvapor", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"A ti te suministra viajes rápidos, y a los enemigos, explosiones enormes.\"\nBotín:\nTesoro de Bonvapor\nZona:\nMinahonda"}
MultiLanguageSpellData['es'][466016] = {name = "Especial de Suprarrayador", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Smaks está seguro de que este cohete no explotará en pleno bueno. En serio. 100% verídico. De verdad. Pero de verdad de la buena.\"\nVendedor:\nSmaks Suprarrayador\nZona:\nMinahonda\nCoste:\n11375"}
MultiLanguageSpellData['es'][466017] = {name = "Investigador de innovaciones", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Cuando el mejor camino hacia una buena idea es ir muy rápido.\"\nVendedora:\nSkedgit Flequilloceniza\nZona:\nMinahonda\nCoste:\n25"}
MultiLanguageSpellData['es'][466018] = {name = "Demoledor Fundisombras", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Se le da de maravilla liar las cosas. Limpiarlas, no tanto.\"\nVendedor:\nSitch Rastrero\nZona:\nMinahonda\nCoste:\n11375"}
MultiLanguageSpellData['es'][466019] = {name = "Trituradora de Aguasnegras deluxe Mk. 2", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Mejor no preguntes qué le pasó al n.º 1.\"\nVendedora:\nContramaestre HardeeZona:\nMinahondaCoste:\n8125"}
MultiLanguageSpellData['es'][466020] = {name = "C.H.A.T.A.R.R.A.dor goblin personalizado", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Las trituradoras goblins han demostrado en incontables ocasiones su utilidad en muchos trabajos, como la explotación forestal y el transporte. Este modelo ha sido reutilizado para C.H.A.T.A.R.R.A.\"\nBotín:\nMontón de chatarra revisado\nZona:\nMinahonda"}
MultiLanguageSpellData['es'][466021] = {name = "Trituradora goblin violeta", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Esta trituradora se ha pintado con esmero utilizando una pintura anticorrosiva para garantizar un brillo duradero.\"\nBotín:\nEnvíos y Portes\nZona:\nMinahonda"}
MultiLanguageSpellData['es'][466022] = {name = "Coordinador de Ventura y Cía.", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Construido para gestionar cualquier operación de Ventura y Cía. desde la vanguardia.\"\nBotín:\nTesoro de Ventura y Cía.\nZona:\nMinahonda"}
MultiLanguageSpellData['es'][466023] = {name = "Defensor de recursos", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Asegura a los demás que tus recursos están exactamente donde deben.\"\nVendedora:\nSkedgit FlequillocenizaZona:\nMinahondaCoste:\n25"}
MultiLanguageSpellData['es'][466024] = {name = "Bombardero de Pantoque", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Ideal para el transporte rápido de las mercancías de los cárteles y otras sustancias altamente volátiles.\"\nBotín:\nTesoro de Pantoque\nZona:\nMinahonda"}
MultiLanguageSpellData['es'][466025] = {name = "Manipulador de márgenes", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Asegura que siempre existe un margen de distancia entre el fondo y tú.\"\nVendedora:\nSkedgit Flequilloceniza\nZona:\nMinahonda\nCoste:\n25"}
MultiLanguageSpellData['es'][466026] = {name = "Máquina voladora de muchimillonario goblin saqueada", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Esta máquina voladora, preciada posesión de la élite goblin en su día, quedó tristemente relegada al desguace tras la llegada al mercado de algo más grande, brillante y explosivo.\"\nBotín:\nBasura de El Gallagio\nZona:\nMinahonda"}
MultiLanguageSpellData['es'][466027] = {name = "Ojo espía de Fundisombras", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Perfecta para cualquier empresario prometedor que quiera escalar posiciones convirtiendo el negocio de los demás en SU negocio.\"\nMisión del mundo:\nPrecipitante de Fundisombras\nZona:\nMinahonda"}
MultiLanguageSpellData['es'][466028] = {name = "Máquina voladora verde y malvada", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Los mejores ingenieros del cártel Bonvapor afirman que fueron ellos quienes inventaron esta obra maestra y que el resto de los cárteles copiaron sus planos.\"\nVendedora:\nAyudante de laboratorio Laszly\nZona:\nMinahonda\nCoste:\n11375"}
