MultiLanguageSpellData['es'][466121] = {name = "Turbodescarga", additional_info = "Rango ilimitado\nInstante\n[q]Geezle emite unos haces de rayos ultramortíferos que infligen 8485573 p. de daño de Naturaleza y aturden a los jugadores golpeados durante 1 s."}
MultiLanguageSpellData['es'][466124] = {name = "Turbocarga", additional_info = "Rango ilimitado\nInstante\n[q]Geezle reconduce la potencia del generador hacia su batería para obtener 10 p. de electricidad e infligir 1091002 p. de daño de Naturaleza a todos los jugadores cada 1 s durante 10 s."}
