MultiLanguageSpellData['es'][466133] = {name = "Trotón de explorador de profundidades", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a tu trotón de explorador de profundidades.\n\n Esta montura puede usar Acompañar.\n[q]\"Esta nave te ayudará a adentrarte en la aventura. ¡Al menos, si no explota antes!\"\nMisión del mundo:\nQuiero que me devuelvan el sombrero\nZona:\nIsla de Dorn\nZona:\nDornogal"}
