MultiLanguageSpellData['es'][466144] = {name = "Murciélago vil de Gladiador preciado", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Despertado de las cuevas en el campo de batalla, y blindado para la refriega.\"\nLogro:\nGladiador: temporada 2 de The War Within\nCategoría:\nJugador contra jugador"}
