MultiLanguageSpellData['es'][466147] = {name = "Enjambre buscador", additional_info = "Instante\n[q]Tichondrius suelta una oleada de magia caótica sobre todos los jugadores afectados por Peste carroñera. Este efecto inflige 24 p. de daño de las Sombras a todos los jugadores en una línea hacia cada objetivo. Además, aplica Peste carroñera a todos los jugadores alcanzados."}
MultiLanguageSpellData['es'][466148] = {name = "Montonazos de bombas enormes", additional_info = "Rango ilimitado\nInstante\n[q]Gallywix pide unos explosivos que explotan (la mayoría) un momento más tarde para infligir 12600019 p. de daño de Fuego y aplicar Quemaduras de explosión .\n\n Sin embargo, parte del fulminante del lote se esparce por la zona."}
