MultiLanguageSpellData['es'][466152] = {name = "Vientos envolventes", additional_info = "Alcance de 5 - 100 m\nHechizo de 2 seg\n[q]Durante un máximo de 10 s, Osirio el Sinmarcas rodea a un enemigo con un ciclón que inflige 10 p. de daño de Naturaleza y 8 p. más de daño de Naturaleza cada 2 s. El objetivo se liberará de los vientos aprisionadores si recibe daño."}
