MultiLanguageSpellData['es'][466990] = {name = "Fuego devastador", additional_info = "[q]Puntería\n Mientras Disparo certero está activo, sucumbes a la oscuridad y obtienes Fuego devastador y Arremetida mortal.\n\n Fuego devastador\n Al lanzar Flecha negra, disparas 2 flechas negras más contra objetivos cercanos, con un 50% de efectividad y priorizando a enemigos que no están afectados por el efecto de daño en el tiempo de Flecha negra.\n\nBestias\n Mientras Llamada de lo salvaje está activa, sucumbes a la oscuridad y obtienes Fuego devastador y Arremetida mortal cada 4 s.\n\n Fuego devastador\n Al lanzar Flecha negra, disparas 2 flechas negras más contra objetivos cercanos, con un 50% de efectividad y priorizando a enemigos que no están afectados por el efecto de daño en el tiempo de Flecha negra."}
MultiLanguageSpellData['es'][466991] = {name = "Fuego devastador", additional_info = "Instante\n[q]Puntería\nMientras Disparo certero está activo, sucumbes a la oscuridad y obtienes Fuego devastador y Arremetida mortal.\n\n Fuego devastador\n Al lanzar Flecha negra, disparas 2 flechas negras más contra objetivos cercanos, con un 50% de efectividad y priorizando a enemigos que no están afectados por el efecto de daño en el tiempo de Flecha negra.\n\nBestias\nMientras Llamada de lo salvaje está activa, sucumbes a la oscuridad y obtienes Fuego devastador y Arremetida mortal cada 4 s.\n\n Fuego devastador\n Al lanzar Flecha negra, disparas 2 flechas negras más contra objetivos cercanos, con un 50% de efectividad y priorizando a enemigos que no están afectados por el efecto de daño en el tiempo de Flecha negra."}
