MultiLanguageSpellData['es'][467024] = {name = "Transportador de Kaja'Cola", additional_info = "[q]Ahora, las curiosidades extraviadas tienen un 35% de probabilidad de contener 1 Kaja'Colas. Además, Brann invoca una caja de seis Kaja'Colas al crear hogueras una vez en cada profundidad.\n\n Hay varios sabores de Kaja'Cola, cada uno con su propio efecto, que se aplica al recogerla."}
MultiLanguageSpellData['es'][467026] = {name = "Granada rebotadora goblomagnética", additional_info = "[q]Durante el combate, existe la posibilidad de que Brann lance una granada goblomagnética que infligirá daño de Naturaleza moderado al enemigo, con un 20% de probabilidades de aturdir durante 1.5 s. Tiene un 25% de probabilidades de rebotar a otro objetivo.\n\n La granada puede rebotar sin peligro hacia los miembros del grupo."}
MultiLanguageSpellData['es'][467029] = {name = "Matriz de conversión de impactos", additional_info = "[q]Al entrar en combate, Brann activa la matriz de conversión durante 10 s. Un pequeño porcentaje de todo el daño infligido por el grupo durante ese periodo aumenta las estadísticas principales de sus miembros.\n\n Después de apagarse la matriz de conversión, el beneficio de las estadísticas principales persiste durante 10 s. Este efecto no puede ocurrir más de una vez cada 2 min."}
MultiLanguageSpellData['es'][467031] = {name = "Torrente de sangre negra", additional_info = "Rango ilimitado\nInstante\n[q]Brota del techo de la fábrica una sangre negra que inflige 14 p. de daño de las Sombras cada 0.5 s."}
MultiLanguageSpellData['es'][467032] = {name = "Fuego de huevo", additional_info = nil}
MultiLanguageSpellData['es'][467033] = {name = "D3SP-0-J4-D0-R", additional_info = "[q]Cada 60 s o tras 5 s después de entrar en combate, analiza el entorno para resaltar curiosidades extraviadas y hacer que los enemigos con menos de un 95% de salud reciban un 4% más de daño durante 10 s."}
MultiLanguageSpellData['es'][467034] = {name = "Bomba de la muerte goblin de ingeniería inversa", additional_info = "[q]Cuando la salud de cualquier jugador cae por debajo del 50% durante el combate, Brann lanza una bomba gigante que explota al impactar.\n\n La explosión repele a los enemigos cercanos y los ralentiza un 45% durante 5 s. Además, sana un 35% de su salud máxima a los miembros del grupo cercanos. Solo puede ocurrir cada 1.5 min."}
MultiLanguageSpellData['es'][467035] = {name = "Imán cómicamente grande", additional_info = "[q]Cuando Brann usa Herramientas de recolección , hay un 100% de probabilidades de que magnetice blindaje desechado para miembros del grupo, que reciben un 5% de su salud máxima como un escudo que se regenera cuando no están en combate.\n\n Herramientas de recolección\nBrann usa sus herramientas de recolección para ayudar a los jugadores a encontrar más oro, menas, hierbas, peces, cueros y tesoros."}
MultiLanguageSpellData['es'][467036] = {name = "Equipamiento propulsor de biocombustible", additional_info = "[q]Los miembros del grupo se equipan con Equipamiento propulsor de biocombustible .\n\n Biocombustible\n Cada enemigo asesinado alimenta el Equipamiento propulsor de biocombustible , lo que aumenta un 2% la velocidad de movimiento y un 2% la celeridad durante 10 s. Se acumula hasta 10 veces."}
MultiLanguageSpellData['es'][467037] = {name = "Chip de aumento marcado", additional_info = "[q]La salud máxima de Brann aumenta un 4%, y el daño infligido y la sanación realizada, un 20%.\n\n Mientras está en combate, Brann puede convertirse en el objetivo de robots mecánicos, que pueden ser destruidos o disipados. Si alcanzan a Brann, perderá un 30% de su salud máxima como daño y quedará aturdido durante 5 s."}
