MultiLanguageSpellData['es'][467306] = {name = "Tótems vivaces", additional_info = "[q][ Mejora : Existe la posibilidad de que Latigazo de lava invoque un tótem abrasador que lanzará Descargas abrasadoras para infligir ([65.205% of Spell Power]) p. de daño de Fuego a un enemigo cercano. Dura 8 s.\n\n Los Choques de Escarcha potenciados por Granizada, Latigazo de lava y Nova de Fuego hacen que tus tótems abrasadores disparen una Tromba abrasadora que inflige ([92.736% of Spell Power]) p. de daño de Fuego a un máximo de 5 enemigos cercanos /\n\nRestauración\nCuando invocas un tótem Marea de sanación, Corriente de sanación, Ráfaga de nubes o Enlace de espíritu, lanzas Sanación en cadena instantáneamente y sin coste con un 100% de efectividad ]"}
MultiLanguageSpellData['es'][467307] = {name = "Patada del viento impetuoso", additional_info = "2.5% del maná base\n{Instante} {10 seg de reutilización}\n[q]Tejedor de niebla ( Monje Tejedor de niebla )\n Lanzas una poderosa ráfaga de viento que inflige ([179.75% of Attack Power]) p. de daño de Naturaleza en un cono de 25 m a los enemigos que tienes delante, a dividir a partes iguales entre todos ellos. El daño aumenta un 6% por cada objetivo golpeado, hasta un máximo de un 30%.\n\n Otorga Vientos impetuosos durante 4 s, lo que aumenta un 200% la sanación de Niebla renovadora.\n\n\n Lanzas una poderosa ráfaga de viento que inflige ([179.75% of Attack Power]) p. de daño de Naturaleza en un cono de 25 m a los enemigos que tienes delante, a dividir a partes iguales entre todos ellos. El daño aumenta un 6% por cada objetivo golpeado, hasta un máximo de un 30%.\n\n Otorga Vientos impetuosos durante 4 s, lo que aumenta un 200% la sanación de Niebla renovadora."}
