MultiLanguageSpellData['es'][468033] = {name = "Runa vinculada a la tormenta de taumaturgo de runas", additional_info = "[q]La runa se sobrecarga por cada 6 s pasados en combate y ataca a un enemigo cercano con un relámpago que inflige 187 p. de daño de Naturaleza.\n\n Este efecto se activa al instante al golpear a una criatura por primera vez."}
MultiLanguageSpellData['es'][468034] = {name = "Orbe de doblegaolas Marea Oscura", additional_info = "Aproximadamente 4 activaciones por minuto\n[q]Existe la posibilidad de que tus hechizos y facultades a distancia le lancen un pegote de agua a un enemigo, lo que le infligirá 259 p. de daño de Escarcha a él y a otros 4 enemigos en un radio de 7 m a su alrededor."}
