MultiLanguageSpellData['es'][470168] = {name = "Céfiro de Cyrce", additional_info = "Instante\n[q]Mientras tengas equipado el aro de Cyrce y estés en la Isla de la Sirena, existe la posibilidad de que tus hechizos y facultades invoquen el céfiro de Cyrce, que lanzará todas las facultades de citrino cantarín existentes a lo largo de 3 s."}
