MultiLanguageSpellData['es'][470197] = {name = "Bendición del morador del mar", additional_info = "Instante\n[q]Obtienes la capacidad pasiva de caminar por el lecho marino, encontrar tesoros submarinos, respirar bajo el agua y nadar mucho más rápido en las aguas alrededor de la Isla de la Sirena.\n\n Necesitas tener el aro de Cyrce equipado."}
