MultiLanguageSpellData['es'][470596] = {name = "Ráfaga de Pirofrío", additional_info = "Alcance de 100 m\nInstante\n[q]Escarcha\nAl lanzar Lluvia de cometas, tu siguiente lanzamiento de Lanza de hielo genera una Ráfaga de Pirofrío que inflige ([265.6% of Spell Power]) p. de daño de Pirofrío a los enemigos cercanos. El daño se reduce cuando afecta a más de 8 objetivos.\n\n Ráfaga de Pirofrío tiene un 50% de probabilidades de otorgar Congelación cerebral.\n\nFuego\nAl lanzar Meteoro, tu siguiente lanzamiento de Explosión de Fuego genera una Ráfaga de Pirofrío que inflige ([265.6% of Spell Power]) p. de daño de Pirofrío a los enemigos cercanos. El daño se reduce cuando afecta a más de 8 objetivos.\n\n Ráfaga de Pirofrío reduce 5 s el tiempo de reutilización de Llamas de fénix."}
MultiLanguageSpellData['es'][470598] = {name = "Ruego al Señor del Fuego", additional_info = "Instante\n[q]Cuando se reduce la salud de Dagran por debajo del 70%, este le pide ayuda al Señor del Fuego y obtiene un escudo que absorbe 38722016 p. de daño.\n\n Un avatar de Ragnaros se une a la batalla e inflige 3872202 p. de daño de Fuego a todos los jugadores. El daño se reduce cuanto más lejos se está del punto de impacto."}
