MultiLanguageSpellData['es'][471363] = {name = "En la cabeza", additional_info = "[q]Ahora, Disparo mortal puede beneficiarse de Disparos precisos con un 25% de efectividad.\n\n Disparo mortal consume Disparos precisos."}
MultiLanguageSpellData['es'][471365] = {name = "Minahonda", additional_info = "Instante\n[q]Habilidad recomendada: 375 p.\n\n De las distintas tuberías emanan canales de Escorrentía Bonvapor. Sus aguas solo están habitadas por los peces más resistentes de Khaz Algar y cualquier otra cosa capaz de aguantar el líquido acre.\n\n Bancos de pesca en esta zona:\n - Lagoluz\n - Vertido de icor imbuido\n - Escorrentía Bonvapor\nProfesión:\nPesca (225)"}
MultiLanguageSpellData['es'][471366] = {name = "Cuerda de tracción", additional_info = "[q]Mientras Disparo certero está activo, el consumo de Disparos precisos extiende 1.0 s la duración de Disparo certero, hasta un máximo de 5.0 s.\n\n Además, Disparo certero aumenta un 50% la efectividad de Aerodinamizar."}
MultiLanguageSpellData['es'][471368] = {name = "Lonja de \"oro\" de Blair", additional_info = "Alcance de 5 m\nHechizo de 3.2 seg\n[q]Situados en el canal central de la Estación de Vapor, Blair Róbalo y su equipo de pescadores se han interesado especialmente por los peces \"dorados\" que viven en Minahonda.\n\n ¡Pásate por allí para participar en los trabajos de conservación y conseguir recompensas\nProfesión:\nPesca (225)"}
