MultiLanguageSpellData['es'][471419] = {name = "Tormenta de balas", additional_info = "Alcance de 300 m\nCanalizado (Hechizo de 8 seg)\n[q]Mug'Zee gira en el sitio y dispara salvas de rayos y plomo durante 8 s. Mug invoca unas oleadas de rayos atronadoras que infligen 6708070 p. de daño de Naturaleza cada 0.5 s a todos los jugadores en un cono a un lado de Mug'Zee, mientras Zee dispara una lluvia de balas que infligen 7546578 p. de daño físico cada 0.3 s a todos los jugadores en un cono al otro lado de Mug'Zee.\n\n Todo el daño de Tormenta de balas destruye la Cárcel sacudetierras y detona las Minas reptadoras inestables ."}
