MultiLanguageSpellData['es'][472358] = {name = "Mentalidad de manada", additional_info = "[q]Bestias\n Aullido del líder de manada aumenta un 50% el daño de Matar.\n\n La invocación de una bestia reduce 10.0 s el tiempo de reutilización de Disparo con púas.\n\nSupervivencia\n Aullido del líder de manada hace que Matar genere una acumulación adicional de Punta de la lanza.\n\n La invocación de una bestia reduce 10.0 s el tiempo de reutilización de Bomba de fuego salvaje."}
