MultiLanguageSpellData['es'][474067] = {name = "Cola de lanzamiento: Oso marrón de Barbabronce", additional_info = "Rango ilimitado\nInstante\n[q]Brann invoca al oso de la familia, el cual irrumpe en la batalla y lanza por los aires a los enemigos.\n\n Luego se prepara para lanzar una sarta de pisotones que infligen daño, crean una zona que aumenta la probabilidad de esquivar e incrementa la salud máxima."}
