MultiLanguageSpellData['es'][474572] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nTransportador de Kaja'Cola\n[q]Ahora, las curiosidades extraviadas tienen un 35% de probabilidad de contener 1 Kaja'Colas. Además, Brann invoca una caja de seis Kaja'Colas al crear hogueras una vez en cada profundidad.\n\n Hay varios sabores de Kaja'Cola, cada uno con su propio efecto, que se aplica al recogerla.\n\nYa tienes este bibelot en tu colección."}
MultiLanguageSpellData['es'][474573] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nImán cómicamente grande\n[q]Cuando Brann usa Herramientas de recolección , hay un 100 % de probabilidades de que magnetice blindaje desechado para miembros del grupo, que reciben un 5 % de su salud máxima como un escudo que se regenera cuando no están en combate.\n\n Herramientas de recolección\nBrann usa sus herramientas de recolección para ayudar a los jugadores a encontrar más oro, menas, hierbas, peces, cueros y tesoros.\n\nYa tienes este bibelot en tu colección."}
MultiLanguageSpellData['es'][474574] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nEquipamiento propulsor de biocombustible\n[q]Los miembros del grupo se equipan con Equipamiento propulsor de biocombustible .\n\n Biocombustible\n Cada enemigo asesinado alimenta el Equipamiento propulsor de biocombustible , lo que aumenta un 2 % la velocidad de movimiento y un 2 % la celeridad durante 10 s. Se acumula hasta 10 veces.\n\nYa tienes este bibelot en tu colección."}
MultiLanguageSpellData['es'][474576] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nBioimpresora tridimensional\n[q]Al dañar a una criatura de élite por debajo del 40 % de salud, se crea una copia imperfecta de esta con un 50 % de poder para que luche a tu lado. Solo puede haber 1 copia a la vez.\n\n El dispositivo puede fallar y crear copias imperfectas de tu compañero.\n\nYa tienes este bibelot en tu colección."}
MultiLanguageSpellData['es'][474577] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nPilón de sobrecarga\n[q]Tras 30 s de combate, los miembros del grupo y Brann infligen un 5 % más de daño y sanan 20 s p. Solo puede ocurrir una vez por combate.\n\nYa tienes este bibelot en tu colección."}
MultiLanguageSpellData['es'][474578] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nEquipo pacifista\n[q]Durante el combate, se designa un piloto durante 8 s antes de lanzar desde el aire el equipo pacifista Mk. 1 en su ubicación para hacerlo inmune, otorgarle el control del equipo durante 10 s y repeler a los enemigos cercanos.\n\nYa tienes este bibelot en tu colección."}
