MultiLanguageSpellData['es'][474585] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nBioimpresora tridimensional\n[q]Al dañar a una criatura de élite por debajo del 40 % de salud, se crea una copia imperfecta de esta con un 75 % de poder para que luche a tu lado. Solo puede haber 1 copia a la vez.\n\n El dispositivo puede fallar y crear copias imperfectas de tu compañero.\n\nYa tienes este bibelot en tu colección."}
