MultiLanguageSpellData['es'][474588] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nEquipamiento propulsor de biocombustible\n[q]Los miembros del grupo se equipan con Equipamiento propulsor de biocombustible .\n\n Biocombustible\n Cada enemigo asesinado alimenta el Biocombustible , lo que aumenta un 2 % la velocidad de movimiento y un 2 % la celeridad durante 20 s. Se acumula hasta 15 veces.\n\nYa tienes este bibelot en tu colección."}
