MultiLanguageSpellData['es'][474591] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nEquipo pacifista\n[q]Durante el combate, se designa un piloto durante 8 s antes de lanzar desde el aire el equipo pacifista Mk. 2 en su ubicación para hacerlo inmune, otorgarle el control del equipo durante 10 s y repeler a los enemigos cercanos.\n\nYa tienes este bibelot en tu colección."}
