MultiLanguageSpellData['es'][474599] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nEquipo de construcción fácil de mecasaurio\n[q]Huevo épico de Brann ahora alberga 1 mecasaurios que provocan a los enemigos durante ( 4000 / 1000) s mientras están en el huevo.\n\n Además de sus otras facultades, empezarán a dar unos pisotones periódicos que infligirán un una cantidad moderada de daño de Fuego a dividir entre los enemigos cercanos. Los enemigos afectados explotarán tras 5 s y recibirán una cantidad moderada de daño de Fuego.\n\nHuevo épico de Brann\nBrann invoca un huevo de demosaurio. Ojalá eclosione.\n\nYa tienes este bibelot en tu colección."}
MultiLanguageSpellData['es'][474600] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nDispensador de bombalones automático\n[q]Existe la posibilidad de que los hechizos y facultades de Brann suelten 2 bombalones en el campo durante 10 s.\n\n Si chocas con un bombalón, se lo lanzarás de una patada a tu objetivo enemigo e infligirás una cantidad considerable de daño de Fuego a todos los enemigos en un radio de 6 m.\n\nYa tienes este bibelot en tu colección."}
MultiLanguageSpellData['es'][474601] = {name = "Añadiendo", additional_info = "Hechizo de 1.5 seg\nComponentes:\nMatriz de conversión de impactos\n[q]Al entrar en combate, Brann activa la matriz de conversión durante 10 s. Un pequeño porcentaje de todo el daño infligido por el grupo durante ese periodo aumenta las estadísticas principales de sus miembros.\n\n Después de apagarse la matriz de conversión, el beneficio de las estadísticas principales persiste durante 10 s. Este efecto no puede ocurrir más de una vez cada 2 min.\n\nYa tienes este bibelot en tu colección."}
MultiLanguageSpellData['es'][474602] = {name = "Rugicañón de ráfaga ígnea", additional_info = "Alcance de 60 m\nInstante\n[q]Flarendo selecciona a un objetivo mientras carga y luego se queda en el sitio y se prepara para disparar. Cuando está preparado, lanza un haz durante 3 s. El haz inflige 66606435 p. de daño de Fuego cada 0.1 s a los jugadores con los que entra en contacto, que son fulminados."}
