MultiLanguageSpellData['es'][1214689] = {name = "Armas electrocargadas", additional_info = "Rango ilimitado\nInstante\n[q]El equipo de Brann cuenta con mejoras de tecnología punta.\n\nEscudo electrocargado\n La sanación efectiva que recibe Brann emana daño de Naturaleza hacia los enemigos cercanos.\n\nPistola electrocargada\n Cada disparo lanza una corriente eléctrica que atraviesa a los enemigos cercanos y reduce su velocidad de ataque. Al sanar a Brann, se sobrecarga su pistola, lo que hace que inflija más daño.\n\nEscopeta electrocargada\n Cada enemigo alcanzado tiene una probabilidad de ser derribado. Al sanar a Brann, se sobrecarga su escopeta, lo que hace que inflija más daño."}
