MultiLanguageSpellData['es'][1215707] = {name = "Conjunto de clase de paladín Reprensión 11.1 (2 piezas)", additional_info = "Requiere Paladín\nAproximadamente 10 activaciones por minuto\n[q]Existe la posibilidad de que tus hechizos y facultades activen una ¡Racha ganadora! que aumentará 2% el daño de tu Veredicto del templario y Tormenta divina. Se acumula hasta 10 veces. Al gastar poder sagrado en facultades dañinas, hay un 12% de probabilidades de eliminar ¡Racha ganadora! ."}
MultiLanguageSpellData['es'][1215709] = {name = "Conjunto de clase de paladín Reprensión 11.1 (4 piezas)", additional_info = "Requiere Paladín\n[q]Cuando pierdes tu ¡Racha ganadora! , recuperas el último punto de poder sagrado gastado. Además, no puedes perder puntos de poder sagrado durante 4.0 s tras perder la racha, y el daño de tus facultades de poder sagrado aumenta un 10%."}
MultiLanguageSpellData['es'][1215710] = {name = "Conjunto de clase de chamán Mejora 11.1 (2 piezas)", additional_info = "Aproximadamente 10 activaciones por minuto\n[q]Existe la posibilidad de que tus hechizos y facultades activen una ¡Racha ganadora! que aumentará un 5% el daño de tu Golpe de tormenta, tu Latigazo de lava y tu Vientos de fatalidad, hasta un máximo del 25%. Los hechizos y facultades que consuman Arma vorágine tendrán un 1.0% de probabilidades de eliminar ¡Racha ganadora! por cada Arma vorágine consumida."}
MultiLanguageSpellData['es'][1215711] = {name = "Hacer una pregunta", additional_info = "Instante\n[q]Le haces una pregunta al narrador, como adónde debes ir ahora, o le pides más información acerca de la historia."}
MultiLanguageSpellData['es'][1215712] = {name = "Conjunto de clase de chamán Mejora 11.1 (4 piezas)", additional_info = "[q]Cuando pierdes tu ¡Racha ganadora! , los vientos se convierten en Vientos de fatalidad durante 3 s. Cuando los Vientos de fatalidad infligen daño, tu siguiente Estallido de relámpagos inflige un 12.0% más de daño, hasta un máximo del 60.0%. Este efecto puede acumularse hasta 10 veces. Además, Estallido de relámpagos inflige un 75% más de daño a tu objetivo principal.\n(100ms de reutilización)"}
MultiLanguageSpellData['es'][1215713] = {name = "Conjunto de clase de guerrero Armas 11.1 (2 piezas)", additional_info = "Aproximadamente 10 activaciones por minuto\n[q]Existe la posibilidad de que tus facultades inicien una ¡Racha ganadora! que aumentará un 5% el daño de Abrumar. Se acumula hasta un máximo de 10 veces.\n Abrumar tiene un 15% de probabilidades de ponerle fin a tu ¡Racha ganadora!"}
MultiLanguageSpellData['es'][1215714] = {name = "Conjunto de clase de guerrero Furia 11.1 (2 piezas)", additional_info = "Aproximadamente 10 activaciones por minuto\n[q]Existe la posibilidad de que tus facultades inicien una ¡Racha ganadora! , que aumentará un 2% el daño de tu Desenfreno. Se acumula hasta un máximo de 10 veces.\n Desenfreno tiene un 15% de probabilidades de ponerle fin a tu ¡Racha ganadora!"}
MultiLanguageSpellData['es'][1215715] = {name = "Conjunto de clase de guerrero Furia 11.1 (4 piezas)", additional_info = "[q]Cuando obtienes una acumulación de ¡Racha ganadora! , pueden pasar dos cosas: tu siguiente Sed de sangre inflige un 15% más de daño y tiene un 25% de probabilidades más de asestar un golpe crítico; o tu siguiente Arremetida enfurecida inflige un 15% más de daño y genera 2 p. de ira extra."}
MultiLanguageSpellData['es'][1215716] = {name = "Conjunto de clase de guerrero Armas 11.1 (4 piezas)", additional_info = "[q]Cuando tu ¡Racha ganadora! termina, obtienes un 2% de celeridad, y el daño de tu Golpe mortal y Rajar aumenta un 2% por cada acumulación de ¡Racha ganadora! que tuvieses durante 12 s."}
MultiLanguageSpellData['es'][1215717] = {name = "Conjunto de clase de monje Viajero del viento 11.1 (2 piezas)", additional_info = "Aproximadamente 10 activaciones por minuto\n[q]Existe la posibilidad de que tus hechizos y facultades activen una ¡Racha ganadora! , que aumentará un 3% el daño de tu Patada del sol naciente y Patada giratoria de la grulla. Se acumula hasta 10 veces. Patada del sol naciente y Patada giratoria de la grulla tienen un 15% de probabilidades de eliminar ¡Racha ganadora!"}
MultiLanguageSpellData['es'][1215718] = {name = "Conjunto de clase de monje Viajero del viento 11.1 (4 piezas)", additional_info = "[q]Puños de furia aplica 1 acumulación de ¡Racha ganadora! al lanzar la facultad y cuando se termina de canalizar por completo. El daño de tu siguiente Puños de furia aumenta un 8% por cada acumulación cuando se elimina ¡Racha ganadora!\n\n Tu ¡Racha ganadora! siempre se elimina cuando llega al máximo de acumulaciones."}
