MultiLanguageSpellData['es'][1215722] = {name = "Conjunto de clase de pícaro Sutileza 11.1 (4 piezas)", additional_info = "[q]Mientras Danza de las Sombras está activo, no puedes perder tu ¡Racha ganadora! , obtienes una acumulación extra de ¡Racha ganadora! cada vez que vayas a obtener una e infliges un 2% más de daño de las Sombras por cada acumulación de ¡Racha ganadora!"}
