MultiLanguageSpellData['es'][1217096] = {name = "Protección de los etéreos", additional_info = "Instante\nAproximadamente 2 activaciones por minuto\n[q]Tus hechizos y facultades de ayuda tienen muchas probabilidades de fusionar la energía a tu alrededor, lo que te otorgará un escudo que reducirá un 20% el daño recibido hasta un máximo de 2668 p.\n\n Al caer por debajo del 40% de salud, obtienes este efecto con un 500% de efectividad. Este efecto solo puede ocurrir una vez cada 6 min.\n(100ms de reutilización)"}
MultiLanguageSpellData['es'][1217101] = {name = "Siega de los etéreos", additional_info = "Instante\nAproximadamente 2 activaciones por minuto\n[q]Existe la posibilidad de que tus hechizos y facultades de ayuda concentren energías latentes a tu alrededor para infligir 1334 p. de daño Arcano a dividir entre tu objetivo y los enemigos cercanos. Los enemigos con menos de un 35% de salud reciben un 20% más de daño.\n(100ms de reutilización)"}
