MultiLanguageSpellData['es'][1217533] = {name = "Imán de monedas", additional_info = "Alcance de 15 m\nInstante\n[q]Al llegar a 100 p. de energía, el aporreador activa un potente imán que atrae todos los montones de oro en un radio de 15 m y obtiene una acumulación de Pagar para ganar por cada montón de monedas consumido."}
MultiLanguageSpellData['es'][1217535] = {name = "Púas envenenadas", additional_info = "[q]El daño directo de Disparo con púas tiene una probabilidad del 30% de explotar al impactar para aplicar Picadura de serpiente e infligir ([120% of Attack Power]) p. de daño de Naturaleza a los enemigos cercanos. Daño reducido al golpear a más de 8 objetivos.\n\n Picadura de serpiente\nRealiza un disparo que envenena al objetivo, que recibe [ Disparos dentados : [([30% of Attack Power]) * 1.1] / ([30% of Attack Power])] p. de daño de Naturaleza al instante y [ Disparos dentados : [([123.6% of Attack Power]) * 1.1] / ([123.6% of Attack Power])] p. de daño de Naturaleza más durante 18 s. [ Inyección de veneno : El daño de Picadura de serpiente aplica Veneno latente al objetivo. Se acumula hasta 10 veces. [ Bestias : Disparo con púas / Puntería : Disparo de puntería / Supervivencia : Golpe de raptor / Mordisco de mangosta ] consume todas las acumulaciones de Veneno latente e inflige ([20.7% of Attack Power]) p. de daño de Naturaleza al objetivo por cada una de ellas ]"}
