MultiLanguageSpellData['es'][1218305] = {name = "Semental forjado en el Vacío", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Estas bestias, forjadas del mismo modo que sus herraduras antaño, parecen más seres hechos de energía del Vacío que caballos.\"\nBotín:\nZona:\nVisión de Ventormenta (regreso)"}
MultiLanguageSpellData['es'][1218306] = {name = "Madre del grupo marcada por el Vacío", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Esta madre del grupo logró liberarse junto a sus cachorros plantando cara a sus cuidadores corruptos. No obstante, deshacerse de sus cuidadores no los libró del Vacío en este lugar perdido. Enseñó a sus crías a ser bestias aún más peligrosas, y ahora acechan por Orgrimmar llevándole comida mientras compiten por la supervivencia.\"\nBotín:\nZona:\nVisión de Orgrimmar (regreso)"}
MultiLanguageSpellData['es'][1218307] = {name = "Jinete del viento marcado por el Vacío", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Cuando se liberaron las energías del Vacío, casi todos los jinetes del viento se volvieron salvajes. Se mataron entre sí, y también a sus instructores. Los supervivientes cerraron las puertas que llevaban a su nido. Es posible ver algún jinete del viento surcando los cielos, pero ninguno se atreve a volver a su nuevo y mortífero dominio para ver lo que queda.\"\nBotín:\nZona:\nVisión de Orgrimmar (regreso)"}
MultiLanguageSpellData['es'][1218308] = {name = "Inferno incendiario", additional_info = "Instante\n[q]Llamakon lanza una ráfaga ígnea hacia cada una de las velas apagadas para volver a prenderlas e infligir 8487876 p. de daño de Fuego a todos los jugadores que encuentre en su camino.\n\n Las llamas abrasan a todos los jugadores, que reciben 242445 p. de daño de Fuego cada 1 s durante 8 s. Este efecto se acumula."}
MultiLanguageSpellData['es'][1218310] = {name = "Modelo de prueba de electrocupuntura", additional_info = "Alcance de 30 mHechizo de 2 seg 10 min de reutilización\n[q]Hace que recorra el cuerpo del objetivo un voltaje vigorizante que aumenta un 20% la celeridad, reduce un 25% el daño recibido y hace que emita daño de Naturaleza durante 3 min.\n\n Se puede usar con la mayoría de las criaturas poco comunes de Minahonda. El objetivo da información de mercado extra para todos los jugadores mientras está activo."}
MultiLanguageSpellData['es'][1218311] = {name = "Delicatessen de Tragonublo fresca", additional_info = "{Instante} {0.5 seg de reutilización}\n[q]Obtienes más frescura temporalmente."}
