MultiLanguageSpellData['es'][1218314] = {name = "Gusano de sombra de Ny'alotha", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a tu gusano de sombra de Ny'alotha.\n[q]\"Estos precursores de los gusanos del abismo, vestigios del pasado del Imperio Negro, han vuelto a resurgir gracias al ascenso de Ny'alotha.\"\nLogro:\nDominio de las visionesCategoría:\nRegreso a las visiones de N'Zoth"}
MultiLanguageSpellData['es'][1218315] = {name = "Modelo de prueba de electrocupuntura", additional_info = "Alcance de 20 m\nInstante\n[q]Inflige 7 p. de daño de Naturaleza."}
MultiLanguageSpellData['es'][1218316] = {name = "Corrupción de los Aspectos", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a la corrupción de los Aspectos. Esta montura cambia según tu habilidad en equitación y la zona en la que estés.\n[q]\"Gracias al triunfo de N'Zoth, lo que comenzó con Galakrond pudo dar sus frutos. Ahora que los Aspectos ya no existen, se ha completado la corrupción de su especie.\"\nVendedora:\nTori\nZona:\nDornogal\nCoste:\n40000"}
MultiLanguageSpellData['es'][1218317] = {name = "Pantera de cristal del Vacío", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a una pantera de cristal del Vacío que se puede montar.\n[q]\"Aunque las energías del Vacío de las visiones horripilantes corrompieron la gran mayoría de las gemas, lo maestros joyeros aún pueden utilizarlas para fabricar impresionantes monturas como esta.\"\nProfesión:\nJoyería"}
