MultiLanguageSpellData['es'][1222232] = {name = "Cólera del Devorador", additional_info = "Rango ilimitado\nInstante\n[q]Adarus lanza unos orbes de Vacío voraz a varias ubicaciones que infligen 5621532 p. de daño Cósmico a todos los jugadores si no son interceptados.\n\n Adarus concentra su atención en los jugadores que hayan interceptado estos orbes y los ataca constantemente con Consumir , además de aumentar un 100% el daño físico que reciben.\n\n Al eliminarse, se transfiere Cólera del Devorador a un jugador cercano al tiempo que todos los jugadores reciben 2108075 p. de daño Cósmico."}
MultiLanguageSpellData['es'][1222234] = {name = "Runa vantus: Minahonda", additional_info = "Rango ilimitado\nHechizo de 1.5 seg\n[q]Una vez por semana, te armonizas con las energías del jefe de banda seleccionado de Minahonda y obtienes la siguiente aura:\n\nRuna vantus: Liberación de Minahonda\n Aumenta 1500 p. tu versatilidad al enfrentarte a ese jefe. Este efecto dura toda una semana."}
MultiLanguageSpellData['es'][1222239] = {name = "Runa vantus: Minahonda", additional_info = "Rango ilimitado\nHechizo de 1.5 seg\n[q]Una vez por semana, te armonizas con las energías del jefe de banda seleccionado de Minahonda y obtienes la siguiente aura:\n\nRuna vantus: Liberación de Minahonda\n Aumenta 1700 p. tu versatilidad al enfrentarte a ese jefe. Este efecto dura toda una semana."}
