MultiLanguageSpellData['es'][1222244] = {name = "Consumir", additional_info = "Rango ilimitado\nHechizo de 2 seg\n[q]Adarus absorbe la esencia de cualquier jugador con , lo que inflige 3 p. de daño Cósmico y absorbe los siguientes 20  p. de sanación recibidos.\n\n Este estallido aplica Apetito inagotable ."}
MultiLanguageSpellData['es'][1222247] = {name = "Rugido espantoso", additional_info = "Hechizo de 2.5 seg\n[q]El trepador lanza un rugido que inflige 10 p. de daño de las Sombras a los jugadores cercanos y aumenta un 50% el daño que reciben de Rugido espantoso . Este efecto se acumula."}
MultiLanguageSpellData['es'][1222265] = {name = "Vínculo salvaje", additional_info = "Instante\n[q]El maestro y su bestia se llenan de ira, lo que aumenta un 50% su velocidad de ataque durante 20 s."}
MultiLanguageSpellData['es'][1222271] = {name = "Grito del dracoleón", additional_info = "Instante\n[q]Durante el combate, cada 30 s tu siguiente Matar invoca una bestia para que te ayude.\n\n Dracoleón\n Un dracoleón desciende de los cielos y emite un grito de batalla que aumenta un 10% tu daño y el de tus mascotas durante 15 s.\n\n Jabalí\n Un jabalí carga contra tu objetivo 3 veces y, al hacerlo, inflige ([400% of Attack Power]) p. de daño físico al objetivo principal y ([160% of Attack Power]) p. de daño a un máximo de 8 enemigos cercanos.\n\n Oso\n Un oso se une a la refriega y lanza unos ataques desgarradores que infligen ([400% of Attack Power]) p. de daño durante 10 s a un máximo de 8 enemigos cercanos."}
MultiLanguageSpellData['es'][1222275] = {name = "¡Tocar el claxon!", additional_info = "{Instante} {1.5 seg de reutilización}\n[q]Tocas el claxon para que todos a tu alrededor comprendan tus sentimientos."}
