MultiLanguageSpellData['es'][1225038] = {name = "Devastación crepuscular", additional_info = "Instante\nAproximadamente 1 activaciones por minuto\n[q]Aplicas una runa de Devastación crepuscular inferior a un yelmo.\n\n Existe la posibilidad de que tus ataques activen un haz de Devastación crepuscular que infligirá hasta un máximo de ( 1 * 845195 * 3) p. de daño de las Sombras a los enemigos frente a ti.\n\n No se puede aplicar a objetos de nivel inferior a 350. Este efecto es temporal y solo funcionará durante la temporada 2 de The War Within.\n(4s de reutilización)"}
