MultiLanguageSpellData['es'][1226511] = {name = "Erizo de la cosecha primaveral", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"El erizo de la cosecha primaveral está más animado a primera hora de la mañana. Se pasa casi todo el día rebuscando comida o llamando al resto de los erizos de la cosecha.\"\nPuesto comercial"}
MultiLanguageSpellData['es'][1226516] = {name = "Minas Reptaterra", additional_info = nil}
MultiLanguageSpellData['es'][1226531] = {name = "Erizo de la cosecha estival", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Al erizo de la cosecha estival le encanta tomar el sol o darse un baño en un lago de aguas cristalinas. Se le da de maravilla buscar comida, pero antes hay que convencerlo para que lo haga.\"\nPuesto comercial"}
MultiLanguageSpellData['es'][1226532] = {name = "Erizo de la cosecha invernal", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Los erizos de la cosecha invernal suelen ser criaturas nocturnas. Son algo más lentos que el resto de los erizos de la cosecha, pero su resistencia no tiene parangón.\"\nPuesto comercial"}
MultiLanguageSpellData['es'][1226533] = {name = "Erizo de la cosecha otoñal", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Los erizos de la cosecha otoñal destacan por su capacidad para encontrar comida en los meses más fríos. Su agudo sentido del olfato los convierte en compañeros excelentes para buscar comida en el bosque, pero pueden mostrar un comportamiento errático en entornos con muchos aromas.\"\nPuesto comercial"}
