MultiLanguageSpellData['es'][1226851] = {name = "Nuclimera vilnata", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a una nuclimera vilnato. Esta montura cambia según tu habilidad en equitación y la zona en la que estés.\n[q]\"Las nuclimeras fueron una de las primeras especies de Azeroth en ser reclamadas por los señores elementales.\"\nPromoción"}
