MultiLanguageSpellData['es'][1227192] = {name = "Heraldo de Sa'bak", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Las leyendas de los tol'vir hablan de Sa'bak, el gran crocolisco que emergió del valle sagrado del Cráter de Un'Goro. Aunque pocos han visto a Sa'bak en carne y hueso, muchos creen que los guardianes de los titanes lo bendijeron para que salvaguardase los caudalosos ríos de Uldum.\"\nTienda del juego"}
