MultiLanguageSpellData['es'][1227206] = {name = "Runa de Estrellas del infinito superiores", additional_info = "Hechizo de 3.5 seg\nRequiere Armadura\n[q]Aplicas una runa de Estrellas del infinito superiores a un yelmo.\n\n Existe la posibilidad de que tus hechizos y facultades golpeen a un enemigo cercano con una estrella del infinito que infligirá ( 1 * 362226) p. de daño Arcano y aumentará ( 1 * 126779) p. el daño que reciba de tus Estrellas del infinito. Se acumula hasta 6 veces antes de reiniciarse.\n\n No se puede aplicar a objetos de nivel inferior a 350. Este efecto es temporal y solo funcionará durante la temporada 2 de The War Within."}
MultiLanguageSpellData['es'][1227209] = {name = "Ruptura de la nada", additional_info = "Rango ilimitado\nInstante\n[q]Unas masas de piedra chocan contra el suelo para infligir 23 p. de daño físico a los jugadores en un radio de 11 m del impacto.\n\n Durante 20 s, perduran unas fallas de Vacío que atraen a los jugadores a su alcance y les aplican [Corrupción de Vacío] cada 1 s."}
MultiLanguageSpellData['es'][1227210] = {name = "Estrellas del infinito", additional_info = "[q]Aplicas una runa de Estrellas del infinito superiores a un yelmo.\n\n Existe la posibilidad de que tus hechizos y facultades golpeen a un enemigo cercano con una estrella del infinito que infligirá ( 1 * 362226) p. de daño Arcano y aumentará ( 1 * 126779) p. el daño que reciba de tus Estrellas del infinito. Se acumula hasta 6 veces antes de reiniciarse.\n\n No se puede aplicar a objetos de nivel inferior a 350. Este efecto es temporal y solo funcionará durante la temporada 2 de The War Within."}
