MultiLanguageSpellData['es'][1229185] = {name = "Conversor de energía de los etéreos", additional_info = "[q]Cuando la salud de un miembro del grupo cae por debajo del 60%, se materializa un conversor de energía de los etéreos, que inflige un daño moderado a los enemigos cercanos y los provoca durante 4 s. Cuando se agota la provocación, el conversor libera una Ola de éter que sana a los aliados cercanos un 20% de su salud. Se puede activar cada 2 min. Al matar enemigos, se reduce en 2 s el tiempo de reutilización del efecto."}
MultiLanguageSpellData['es'][1229186] = {name = "Conversor de energía de los etéreos", additional_info = "[q]Cuando la salud de un miembro del grupo cae por debajo del 60 %, se materializa un conversor de energía de los etéreos, que inflige un daño moderado a los enemigos cercanos y los provoca durante 4  s. Cuando se agota la provocación, el conversor libera una Ola de éter que sana a los aliados cercanos un 30 % de su salud. Se puede activar cada 2 min. Al matar enemigos, se reduce en 4  s el tiempo de reutilización del efecto."}
MultiLanguageSpellData['es'][1229187] = {name = "Conversor de energía de los etéreos", additional_info = "[q]Cuando la salud de un miembro del grupo cae por debajo del 60 %, se materializa un conversor de energía de los etéreos, que inflige un daño moderado a los enemigos cercanos y los provoca durante 6  s. Cuando se agota la provocación, el conversor libera una Ola de éter que sana a los aliados cercanos un 40 % de su salud. Se puede activar cada 2 min. Al matar enemigos, se reduce en 6  s el tiempo de reutilización del efecto."}
MultiLanguageSpellData['es'][1229188] = {name = "Conversor de energía de los etéreos", additional_info = "[q]Cuando la salud de un miembro del grupo cae por debajo del 60 %, se materializa un conversor de energía de los etéreos, que inflige un daño moderado a los enemigos cercanos y los provoca durante 6  s. Cuando se agota la provocación, el conversor libera una Ola de éter que sana a los aliados cercanos un 50 % de su salud. Se puede activar cada 2 min. Al matar enemigos, se reduce en 8  s el tiempo de reutilización del efecto."}
MultiLanguageSpellData['es'][1229189] = {name = "Gafas tintadas de maná", additional_info = "[q]Durante el combate, Brann se pone unas gafas tintadas de maná que aumentan un 4 % el daño que inflige y un 5 % el daño que recibe de manera periódica cada 5 s hasta 10 veces.\n\n Al disipar las gafas, Brann recupera el 25 % de su salud máxima y aturde a los enemigos cercanos durante 2  s.\n Si no, este efecto se disipa automáticamente cuando la salud de Brann cae por debajo del 30 %, lo que impide el aturdimiento."}
MultiLanguageSpellData['es'][1229190] = {name = "Gafas tintadas de maná", additional_info = "[q]Durante el combate, Brann se pone unas gafas tintadas de maná que aumentan un 4% el daño que inflige y un 5% el daño que recibe de manera periódica cada 5 s hasta 10 veces.\n\n Al disipar las gafas, Brann recupera el 40% de su salud máxima y aturde a los enemigos cercanos durante 3 s.\n Si no, este efecto se disipa automáticamente cuando la salud de Brann cae por debajo del 30%, lo que impide el aturdimiento."}
MultiLanguageSpellData['es'][1229191] = {name = "Gafas tintadas de maná", additional_info = "[q]Durante el combate, Brann se pone unas gafas tintadas de maná que aumentan un 5% el daño que inflige y un 5% el daño que recibe de manera periódica cada 5 s hasta 10 veces.\n\n Al disipar las gafas, Brann recupera el 55% de su salud máxima y aturde a los enemigos cercanos durante 4 s.\n Si no, este efecto se disipa automáticamente cuando la salud de Brann cae por debajo del 30%, lo que impide el aturdimiento."}
