MultiLanguageSpellData['es'][1229197] = {name = "Sombrebumerán", additional_info = "[q]Existe la posibilidad de que Brann saque sombreros al azar y los lance a sus enemigos. Los sombreros infligirán daño moderado y aplicarán 1 perjuicio(s) a 2 objetivos.\n\n Los posibles perjuicios incluyen un 20 % más de daño recibido, un 20 % menos de daño infligido y un 20 % menos de velocidad de ataque y lanzamiento."}
