MultiLanguageSpellData['es'][1229209] = {name = "Cristal desacelerador temporal", additional_info = "[q]Al dañar a una criatura de élite con más del 80% de salud o menos del 20%, Brann activa la energía del cristal, lo que reduce un 20% la velocidad de ataque y de lanzamiento de la criatura de élite durante 30 s. Al matar a la criatura de élite mientras esté activo el perjuicio, el grupo recibirá un beneficio acumulable del 2% de celeridad."}
