MultiLanguageSpellData['es'][1233491] = {name = "Conquista", additional_info = "Rango ilimitado\nCanalizado (Hechizo de 5 seg)\n[q]Salhadaar asesta un terrible golpe que inflige 101187582 p. de daño físico a su objetivo actual y 84322985 p. de daño de las Sombras más que se dividen entre todos los jugadores en un radio de 8 m, además de lanzarlos por los aires.\n\n Los jugadores golpeados pierden una acumulación de Vinculado por el voto . Aumenta un 500% el daño recibido con Conquista durante 20 s."}
