MultiLanguageSpellData['es'][1233515] = {name = "Depósito de Información Segura Contenida y Organizada", additional_info = "[q]Existe la posibilidad de que tus hechizos y facultades te conviertan en un pararrayos que lanzará relámpagos contra un objetivo enemigo aleatorio en un radio de 40 m para infligirle ( 1 * 209 ) p. de daño de Naturaleza cada 3 s durante 15 s."}
MultiLanguageSpellData['es'][1233518] = {name = "K'arroc de lavanda", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"El anterior propietario de este k'arroc especialmente agresivo murió mientras investigaba el Espacio Desvinculado. Tal vez te prefiera a ti... o tal vez no.\"\nVendedor:\nShad'anis\nZona:\nK'aresh\nCoste:\n10"}
