MultiLanguageSpellData['es'][1233539] = {name = "Devorar", additional_info = "Hechizo de 2 seg\n[q]Al llegar a 100 p. de energía, Dimensius aumenta su densidad para crear una poderosa fuerza interna que inflige 1686460 p. de daño de las Sombras cada 1 durante 5 s y atrae a los jugadores, a las estrellas del Vacío, a los agujeros negros y al disco de acrecentamiento.\n\n Tras 5 s, cualquier jugador fuera de un Pozo de gravedad de Estrella del Vacío se ve inmediatamente atraído hacia Dimensius y enviado al Olvido ."}
MultiLanguageSpellData['es'][1233542] = {name = "Escarchahuesos", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Este trepador, rival acérrimo del Fundehuesos, fue expulsado de su guarida cerca de la Forja de Maná Omega tras una aplastante derrota. Ahora busca aprender de quien destronó a su mayor enemigo.\"\nVándalos de la Forja de Maná\nRenombre:\n14\nUbicación:\nPunto Sombrío"}
