MultiLanguageSpellData['es'][1233547] = {name = "Trepador del Vacío ácido", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Este trepador se ha alimentado de emanaciones nocivas, y su cuerpo ha quedado imbuido de ácidos muy potentes.\"\nVendedor:\nShad'anis\nZona:\nK'aresh\nCoste:\n7"}
