MultiLanguageSpellData['es'][1233553] = {name = "Prisma abisal implacable", additional_info = "[q]Tus facultades dañinas extraen Vacío concentrado a través del prisma para infligir ( 441 * 1 ) p. de daño Cósmico a dividir entre tu objetivo y los enemigos cercanos. El daño aumenta un 30% por cada enemigo golpeado, hasta un máximo de un 150%. Este efecto puede suceder una vez cada 10 s y acumula poder latente en el prisma hasta un máximo de 18 veces.\n(10s de reutilización)"}
