MultiLanguageSpellData['es'][1233654] = {name = "Gafas tintadas de maná", additional_info = "Rango ilimitado\nInstante\n[q]Durante el combate, Brann se pone unas gafas tintadas de maná que aumentan un 4% el daño que inflige y un 5% el daño que recibe de manera periódica cada 5 s hasta 10 veces.\n\n Al disipar las gafas, Brann recupera el 40% de su salud máxima y aturde a los enemigos cercanos durante 3 s.\n Si no, este efecto se disipa automáticamente cuando la salud de Brann cae por debajo del 30%, lo que impide el aturdimiento."}
MultiLanguageSpellData['es'][1233655] = {name = "Gafas tintadas de maná", additional_info = "Rango ilimitado\nInstante\n[q]Durante el combate, Brann se pone unas gafas tintadas de maná que aumentan un 5% el daño que inflige y un 5% el daño que recibe de manera periódica cada 5 s hasta 10 veces.\n\n Al disipar las gafas, Brann recupera el 55% de su salud máxima y aturde a los enemigos cercanos durante 4 s.\n Si no, este efecto se disipa automáticamente cuando la salud de Brann cae por debajo del 30%, lo que impide el aturdimiento."}
MultiLanguageSpellData['es'][1233656] = {name = "Gafas tintadas de maná", additional_info = "Rango ilimitado\nInstante\n[q]Durante el combate, Brann se pone unas gafas tintadas de maná que aumentan un 5% el daño que inflige y un 5% el daño que recibe de manera periódica cada 5 s hasta 10 veces.\n\n Al disipar las gafas, Brann recupera el 70% de su salud máxima y aturde a los enemigos cercanos durante 5 s.\n Si no, este efecto se disipa automáticamente cuando la salud de Brann cae por debajo del 30%, lo que impide el aturdimiento."}
