MultiLanguageSpellData['es'][1233693] = {name = "Arenas de K'aresh", additional_info = "Rango ilimitado\nInstante\n[q]Cuando Brann utiliza Herramientas de recolección , las arenas comienzan a arremolinarse en torno a los miembros del grupo, lo que les otorga 8% de golpe crítico hasta 10 veces y ralentiza un 8% a los enemigos cercanos.\n\n Los golpes críticos crean un demonio de arena en la ubicación del objetivo durante 6 s que arrastra a los enemigos hacia el centro periódicamente. Solo puede suceder cada 45 s.\n\nHerramientas de recolección\nBrann usa sus herramientas de recolección para ayudar a los jugadores a encontrar más oro, menas, hierbas, peces, cueros y tesoros."}
MultiLanguageSpellData['es'][1233694] = {name = "Arenas de K'aresh", additional_info = "Rango ilimitado\nInstante\n[q]Cuando Brann utiliza Herramientas de recolección , las arenas comienzan a arremolinarse en torno a los miembros del grupo, lo que les otorga 10% de golpe crítico hasta 10 veces y ralentiza un 10% a los enemigos cercanos.\n\n Los golpes críticos crean un demonio de arena en la ubicación del objetivo durante 6 s que arrastra a los enemigos hacia el centro periódicamente. Solo puede suceder cada 45 s.\n\nHerramientas de recolección\nBrann usa sus herramientas de recolección para ayudar a los jugadores a encontrar más oro, menas, hierbas, peces, cueros y tesoros."}
MultiLanguageSpellData['es'][1233695] = {name = "Arenas de K'aresh", additional_info = "Rango ilimitado\nInstante\n[q]Cuando Brann utiliza Herramientas de recolección , las arenas comienzan a arremolinarse en torno a los miembros del grupo, lo que les otorga 12% de golpe crítico hasta 10 veces y ralentiza un 12% a los enemigos cercanos.\n\n Los golpes críticos crean un demonio de arena en la ubicación del objetivo durante 6 s que arrastra a los enemigos hacia el centro periódicamente. Solo puede suceder cada 45 s.\n\nHerramientas de recolección\nBrann usa sus herramientas de recolección para ayudar a los jugadores a encontrar más oro, menas, hierbas, peces, cueros y tesoros."}
MultiLanguageSpellData['es'][1233699] = {name = "Nova de éter", additional_info = "Alcance de 100 m\nInstante\n[q]Cuando la salud de un miembro del grupo cae por debajo del 60 %, se materializa un conversor de energía de los etéreos, que inflige un daño moderado a los enemigos cercanos y los provoca durante 4  s. Cuando se agota la provocación, el conversor libera una Ola de éter que sana a los aliados cercanos un 30 % de su salud. Se puede activar cada 2 min. Al matar enemigos, se reduce en 4  s el tiempo de reutilización del efecto."}
MultiLanguageSpellData['es'][1233700] = {name = "Nova de éter", additional_info = "Alcance de 100 m\nInstante\n[q]Cuando la salud de un miembro del grupo cae por debajo del 60 %, se materializa un conversor de energía de los etéreos, que inflige un daño moderado a los enemigos cercanos y los provoca durante 6  s. Cuando se agota la provocación, el conversor libera una Ola de éter que sana a los aliados cercanos un 40 % de su salud. Se puede activar cada 2 min. Al matar enemigos, se reduce en 6  s el tiempo de reutilización del efecto."}
