MultiLanguageSpellData['es'][1233894] = {name = "Conducto de viento de cola", additional_info = "Rango ilimitado\nInstante\n[q]Genera una ráfaga de velocidad al salir de combate que aumenta un 60% tu velocidad de movimiento durante 10 s, efecto que decae con el tiempo. Al usar una habilidad defensiva en combate, te rodean unas ráfagas de viento que aplican un escudo equivalente al 30% de la salud que te falte durante 8 s.\n(30s de reutilización)"}
MultiLanguageSpellData['es'][1233895] = {name = "Cristal de amplificación de sonido", additional_info = "Rango ilimitado\nInstante\n[q]La voz de Brann se amplifica moderadamente con magia Arcana, lo que hace que sus palabras puedan otorgar un beneficio al grupo según lo que diga."}
MultiLanguageSpellData['es'][1233896] = {name = "Égida maltrecha", additional_info = "Rango ilimitado\nInstante\n[q]Con la égida equipada, todos los miembros del grupo infligen y aplican un 6% más de daño y sanación. Cada 10 s durante el combate, Brann y tú recuperáis una cantidad de salud equivalente al 10% del daño que hayáis recibido en ese tiempo.\n\n Cuando un jugador muere y revive, la égida le otorga un 2% de reducción de daño y aumenta un 3% la sanación que recibe, pero reduce un 2% el daño que inflige y la sanación que realiza. Se puede acumular hasta 3 veces."}
MultiLanguageSpellData['es'][1233897] = {name = "Cristal desacelerador temporal", additional_info = "Rango ilimitado\nInstante\n[q]Al dañar a una criatura de élite con más del 80% de salud o menos del 20%, Brann activa la energía del cristal, lo que reduce un 30% la velocidad de ataque y de lanzamiento de la criatura de élite durante 30 s. Al matar a la criatura de élite mientras esté activo el perjuicio, el grupo recibirá un beneficio acumulable del 4% de celeridad."}
MultiLanguageSpellData['es'][1233898] = {name = "Dispositivo desconcertante", additional_info = "Rango ilimitado\nInstante\nAproximadamente 2 activaciones por minuto\n[q]Existe la posibilidad de que Brann otorgue un bonus del 10% de salud, daño o sanación a los jugadores durante 20 s según su función de combate seleccionado.\n\n Existe la posibilidad de que los jugadores otorguen a Brann un bonus del 10% de salud, daño o sanación durante 20 s según su rol seleccionado.\n(20s de reutilización)"}
