MultiLanguageSpellData['es'][1235368] = {name = "Tajo Arcano", additional_info = "Alcance de 100 m\nHechizo de 3 seg\n[q]Lanza una energía Arcana en dirección al objetivo actual que inflige 4848899 p. de daño Arcano a los jugadores en un cono y hace que reciban 1697115 p. de daño Arcano más cada 1.5 s durante 9 s. Este efecto se acumula."}
