MultiLanguageSpellData['es'][1235383] = {name = "Embate", additional_info = "{20 p. de energía} {Alcance de ataques cuerpo a cuerpo}\nInstante\nRequiere Arma cuerpo a cuerpo\n[q]Golpea a un adversario y le inflige 42086 p. de daño físico."}
