MultiLanguageSpellData['es'][1235387] = {name = "Latigazo místico de Naazindhri", additional_info = "Aproximadamente 2.5 activaciones por minuto\n[q]Tus hechizos dañinos tienen muchas probabilidades de darle a tu objetivo un latigazo de poder Arcano que infligirá ( 560 * 1 ) p. de daño Arcano a dividir entre el objetivo y los enemigos alcanzados por el camino.\n\n El daño aumenta un 30% por cada enemigo extra, hasta un máximo de un 150%. Aumenta todavía más gracias a tu maestría."}
MultiLanguageSpellData['es'][1235388] = {name = "Cólera de las bestias", additional_info = "Alcance de 100 m\nInstante\n[q]A partir de ahora, las bestias temibles obedecerán tu Matar, que infligirá su daño con un 30% de efectividad.\n\n Cólera de las bestias hace que tus bestias temibles se enfurezcan, lo que aumenta un 15% el daño que infligen durante 15 s. Las bestias temibles invocadas durante Cólera de las bestias se beneficiarán durante un periodo reducido."}
MultiLanguageSpellData['es'][1235391] = {name = "Transformación oscura", additional_info = "Alcance de 100 m\nInstante\n[q]Tu [ Eructador de lodo : abominación ] [ Glifo de geist : geist / necrófago ] inflige ([44.73% of Attack Power]) p. de daño de las Sombras a 5 enemigos cercanos y se transforma en una poderosa monstruosidad no-muerta durante 15 s. [ Transformación oscura : Esto le otorga un 100% de energía. Además, las / Las] facultades [ Eructador de lodo : de la abominación ] [ Glifo de geist : del geist / del necrófago ] se potencian y adquieren nuevas funciones mientras la transformación está activa."}
MultiLanguageSpellData['es'][1235397] = {name = "Alcance umbrío", additional_info = "[q]Puntería\n El daño periódico de Flecha negra aumenta un 100%, y ahora Pólvora desoladora aplica el efecto periódico de Flecha negra a todos los enemigos a los que inflige daño.\n\n Si Pólvora desoladora inflige daño a 2 o más enemigos, obtienes Disparos trucados si dispones del talento.\n\nBestias\n El daño periódico de Flecha negra aumenta un 100%, y ahora Pólvora desoladora aplica el efecto periódico de Flecha negra a todos los enemigos a los que inflige daño.\n\n Si Pólvora desoladora inflige daño a 2 o más enemigos, obtienes Tajo de la bestia si dispones del talento."}
