MultiLanguageSpellData['es'][1235879] = {name = "Encolerizado", additional_info = "Instante\n[q]Al recibir daño te enfureces, lo que hace que absorbas 202 p. de daño e inflijas 461 p. de daño de las Sombras por cada acumulación, a dividir entre los enemigos cercanos. Daño aumentado un 30% por cada enemigo adicional, hasta un máximo de 150%.\n\n Puedes enfurecerte más cada 15 s. Este efecto se acumula hasta 15 veces, pero no tardarás en calmarte tras abandonar el combate.\n\nSolo válido para las especializaciones de tanque."}
