MultiLanguageSpellData['es'][1235934] = {name = "Martillo de Luz", additional_info = "Alcance de 100 m\nInstante Requiere Paladín\n[q]Golpea a tu enemigo con el poder de la Luz, que inflige ([580.645% of Attack Power]) p. de daño Sagrado y ([290% of Attack Power]) p. de daño Sagrado más a un máximo de 4 enemigos cercanos.\n\n Además, invoca unos martillos empíreos que descienden desde los cielos para golpear a 3 enemigos cercanos, cada uno de los cuales recibe ([46.55% of Attack Power]) p. de daño Sagrado."}
MultiLanguageSpellData['es'][1235946] = {name = "Marca de ira incesante", additional_info = "Instante\n[q]Al recibir daño te enfureces, lo que hace que absorbas 202 p. de daño e inflijas 461 p. de daño de las Sombras por cada acumulación, a dividir entre los enemigos cercanos. Daño aumentado un 30% por cada enemigo adicional, hasta un máximo de 150%.\n\n Puedes enfurecerte más cada 15 s. Este efecto se acumula hasta 15 veces, pero no tardarás en calmarte tras abandonar el combate.\n\nSolo válido para las especializaciones de tanque."}
MultiLanguageSpellData['es'][1235959] = {name = "Mage Spellslinger 11.2 Class Set 2pc", additional_info = "[q]Arcano\n El daño de Explosión Arcana aumenta un 12% y Explosión Arcana otorga 1 acumulación de Armonía Arcana. El daño directo de Astillar tiene un 25% de probabilidades de otorgar una acumulación de Armonía Arcana.\n\nFuego, Escarcha\n El daño de Lanza de hielo y Carámbano aumenta un 10%, y Lanza de hielo tiene un 50% de probabilidades de generar 1 acumulación de Frente frío. El daño directo de Astillar tiene un 15% de probabilidades de otorgar una acumulación de Frente frío."}
MultiLanguageSpellData['es'][1235962] = {name = "Mage Sunfury 11.2 Class Set 2pc", additional_info = "[q]Arcano, Fuego, Escarcha\n Bonus de daño con hechizos de Esfera Piroarcana aumentado un 1.0%. Ahora, Cascada de maná otorga un 0.5% más de celeridad por acumulación."}
MultiLanguageSpellData['es'][1235963] = {name = "Mage Frostfire 11.2 Class Set 2pc", additional_info = "[q]Fuego\n El daño de Lluvia de cometas y Ráfaga de Pirofrío aumenta un 15%. El daño de Descarga de Pirofrío aumenta un 8%. Lluvia de cometas, Ráfaga de Pirofrío y Descarga de Pirofrío aplican Ignición con un 75% de efectividad.\n\nArcano, Escarcha\n El daño de Meteoro y de Ráfaga de Pirofrío aumenta un 30%. El daño de Descarga de Pirofrío aumenta un 10%. Meteoro, Ráfaga de Pirofrío y Descarga de Pirofrío aplican Ignición, que inflige un 25% más de daño durante 9 s."}
MultiLanguageSpellData['es'][1235964] = {name = "Mage Spellslinger 11.2 Class Set 4pc", additional_info = "[q]Escarcha\n Cuando Orbe congelado inflige daño a uno o más enemigos, tiene un 15% de probabilidades de otorgar una acumulación de Frente frío. Cuando Frente frío invoca un Orbe congelado, aumenta un 8% tu daño con hechizos durante 10 s.\n\nArcano\n Daño de Astillar aumentado un 8%. Orbe Arcano tiene un 100% de probabilidades de otorgar una acumulación de Armonía Arcana, hasta un máximo de 8 veces. Al llegar a 20 acumulaciones de Armonía Arcana, obtienes Intuición con un 100% de efectividad..\n\nFuego\n Daño de Astillar aumentado un 8%. Orbe Arcano tiene un 100% de probabilidades de otorgar una acumulación de Armonía Arcana, hasta un máximo de 8 veces. Cuando Frente frío invoca un Orbe congelado, aumenta un 8% tu daño con hechizos durante 10 s.\n\n(100ms de reutilización)"}
MultiLanguageSpellData['es'][1235965] = {name = "Mage Sunfury 11.2 Class Set 4pc", additional_info = "[q]Fuego, Escarcha\n El lanzamiento de hechizos excepcionales por parte de tu fénix añade 0.3 s más a la duración de tu siguiente Hipertermia. Cuando tu fénix se agota, te potencia todavía más al otorgarte Distorsión temporal inferior y un 10% más de daño con hechizos durante 10 s.\n\nArcano\n El lanzamiento de hechizos excepcionales por parte de tu fénix añade 0.5 s más a la duración de tu siguiente Alma Arcana. Cuando tu fénix se agota, te potencia todavía más al otorgarte Distorsión temporal inferior y un 20% más de daño con hechizos durante 10 s."}
MultiLanguageSpellData['es'][1235966] = {name = "Mage Frostfire 11.2 Class Set 4pc", additional_info = "[q]Arcano, Escarcha\n Cuando se lanza Pica glacial, hay un 100% de probabilidades de lanzar también Piroexplosión, que inflige ([352.5% of Spell Power]) p. de daño de Fuego. Además, Piroexplosión se beneficia ahora de Ignición.\n\nFuego\n Cuando se lanza Piroexplosión, hay un 20% de probabilidades de lanzar también Pica glacial, que inflige ([366.24% of Spell Power]) p. de daño de Escarcha. Las Picas glaciales lanzadas de este modo no tendrán efectos de enraizamiento. Además, Pica glacial se beneficia ahora de Ignición."}
