MultiLanguageSpellData['es'][1236207] = {name = "Oleada astral", additional_info = "Rango ilimitado\nInstante\n[q]El recolector Arcano rebosa de energía si entra en contacto con una manifestación Arcana e inflige 22623435 p. de daño Arcano a todos los jugadores y 8432299 p. de daño Arcano más cada 2 s durante 16 s."}
MultiLanguageSpellData['es'][1236209] = {name = "Pica glacial", additional_info = "{1% del maná base} {Alcance de 40 m}\nHechizo de 2.75 seg\n[q]Crea una enorme púa de hielo que se fusiona con tus carámbanos actuales. La púa empala al objetivo y le inflige ([654% of Spell Power]) p. de daño más el daño que almacenaban los carámbanos, y congela al objetivo en el sitio durante 4 s. El daño puede interrumpir el efecto de congelación.\n\n Para lanzarla, hacen falta 5 carámbanos.\n\nPasiva: Lanza de hielo ya no arroja carámbanos."}
MultiLanguageSpellData['es'][1236211] = {name = "Pica glacial", additional_info = "Alcance de 100 m\nInstante\n[q]Crea una enorme púa de hielo que se fusiona con tus carámbanos actuales. La púa empala al objetivo y le inflige ([654% of Spell Power]) p. de daño más el daño que almacenaban los carámbanos, y congela al objetivo en el sitio durante 4 s. El daño puede interrumpir el efecto de congelación.\n\n Para lanzarla hacen falta 5 carámbanos.\n\nPasiva: Lanza de hielo ya no arroja carámbanos."}
