MultiLanguageSpellData['es'][1236330] = {name = "Druid Druid of the Claw 11.2 Class Set 4pc", additional_info = "[q]Feral\n Despedazar tiene un 40% de probabilidades de hacer que uses Despedazar otra vez contra tu objetivo 4 s después con un 100% del poder inicial.\n\nEquilibrio, Guardián, Restauración\n Despedazar tiene un 40% de probabilidades de hacer que uses Despedazar otra vez contra tu objetivo 4 s después con un 60% de efectividad."}
MultiLanguageSpellData['es'][1236331] = {name = "Druid Druid of the Claw 11.2 Class Set 2pc", additional_info = "[q]Despedazar aumenta un 10% tu celeridad, un 10% tu probabilidad de golpe crítico y un 30% el daño que infligen tus hemorragias durante 5 s.\n(100ms de reutilización)"}
MultiLanguageSpellData['es'][1236332] = {name = "Druid Elune's Chosen 11.2 Class Set 2pc", additional_info = "[q]Equilibrio\n El daño de Fuego estelar aumenta un 20%. Al obtener poder astral con Fuego estelar hay un 40% de probabilidades de lanzar una Oleada de estrellas a una víctima con un 45% de efectividad.\n\nFeral, Guardián, Restauración\n El daño de Vapulear aumenta un 20%. Vapulear hay un 40% de probabilidades de lanzar una Oleada de estrellas a una víctima con un 160% de efectividad.\n\n(100ms de reutilización)"}
MultiLanguageSpellData['es'][1236333] = {name = "Druid Elune's Chosen 11.2 Class Set 4pc", additional_info = "[q]Equilibrio\n Al impactar, las Oleadas de estrellas lanzadas por Fuego estelar se dividen entre un máximo de 3 objetivos más con un 40% de efectividad y otorgan una acumulación de Recolectar luz de luna. Al lanzar Furia de Elune o Luna llena, se consume Recolectar luz de luna para aumentar un 4% tu daño por cada acumulación durante 12 s.\n\nFeral, Guardián, Restauración\n Al impactar, las Oleadas de estrellas lanzadas por Vapulear se dividen entre un máximo de 3 objetivos más con un 20% de efectividad y otorgan una acumulación de Recolectar luz de luna. Al lanzar Haz lunar, se consume Recolectar luz de luna para aumentar un 4% tu daño por cada acumulación durante 12 s."}
MultiLanguageSpellData['es'][1236334] = {name = "Druid Keeper of the Grove 11.2 Class Set 2pc", additional_info = "[q]Equilibrio, Feral, Guardián\n Al lanzar Alineación celestial, se convoca la ayuda de una dríade durante 10 s que lanza Oleada de estrellas con un 360% de efectividad y Lluvia de estrellas con un 800% de efectividad.\n\nRestauración\n Al lanzar Encarnación: Árbol de vida o Convocar a los espíritus, se convoca la ayuda de una dríade durante 5 s que lanza Tranquilidad con un 50% de efectividad y lanza Recrecimiento inmediatamente con un 200% de efectividad a tu aliado con menos salud"}
MultiLanguageSpellData['es'][1236336] = {name = "Druid Keeper of the Grove 11.2 Class Set 4pc", additional_info = "[q]Restauración\n Cuando tu Dríade se desvanece, tus siguientes 2Alivio presto sanan una cantidad equivalente al 5% de tu sanación realizada mientras estaba activa y salpican con un 25% de su sanación a aliados cercanos. Este efecto se reduce a partir de 5 objetivos.\n\nEquilibrio, Feral, Guardián\n Cuando tu Dríade se desvanece, tus siguientes 2Oleada de estrellas infligen una cantidad equivalente al 3% de tu daño infligido mientras estaba activa y salpican con un 10% de su daño a enemigos cercanos. Este efecto se reduce a partir de 5 objetivos."}
MultiLanguageSpellData['es'][1236337] = {name = "Druid Wildstalker 11.2 Class Set 2pc", additional_info = "[q]Equilibrio, Guardián, Restauración\n El ritmo al que crece Florecimientos simbióticos aumenta un 45%. Al lanzar Recrecimiento con Lanzamiento libre, Florecimientos simbióticos crece en un máximo de 2 aliados cercanos válidos.\n\nFeral\n El ritmo al que crece Vides buscasangre aumenta un 40%. Furia del tigre hace que Vides buscasangre crezca hasta en 3 enemigos cercanos válidos."}
MultiLanguageSpellData['es'][1236338] = {name = "Druid Wildstalker 11.2 Class Set 4pc", additional_info = "[q]Equilibrio, Guardián, Restauración\n Florecimientos simbióticos tiene un 35% de probabilidades de activar Crecimiento detonante cada 2 s con un 100% de efectividad. Cada acumulación de Florecimientos simbióticos en un aliado aumenta un 30% la sanación recibida de Crecimiento detonante.\n\nFeral\n Vides buscasangre tiene un 20% de probabilidades de activar Crecimiento detonante cada 2 s con un 100% de efectividad. Cada acumulación de Vides buscasangre en un enemigo aumenta un 40% el daño recibido de Crecimiento detonante."}
MultiLanguageSpellData['es'][1236342] = {name = "Preparando el golpe", additional_info = "Instante\n[q]Feral\nDespedazar tiene un 40% de probabilidades de hacer que uses Despedazar otra vez contra tu objetivo 4 s después con un 100% del poder inicial.\n\nEquilibrio, Guardián, Restauración\nDespedazar tiene un 40% de probabilidades de hacer que uses Despedazar otra vez contra tu objetivo 4 s después con un 60% de efectividad."}
MultiLanguageSpellData['es'][1236343] = {name = "Detonación abismal", additional_info = nil}
MultiLanguageSpellData['es'][1236348] = {name = "Tajo cargado", additional_info = "Alcance de 100 mHechizo de 4 seg 3 seg de reutilización\n[q]Zo'phex carga sus espadas y asesta un tajo masivo que inflige 15758921 p. de daño físico a todos los enemigos frente a él."}
MultiLanguageSpellData['es'][1236350] = {name = "Void Power Shard Released Visuals - COSMETIC", additional_info = nil}
MultiLanguageSpellData['es'][1236354] = {name = "Succión de alma", additional_info = "Alcance de 40 mHechizo de 2 seg 5 seg de reutilización\n[q]El taumaturgo ralentiza a su objetivo y le absorbe 622547 p. de salud durante 8 s, además de sanarse él dos veces la cantidad absorbida."}
MultiLanguageSpellData['es'][1236355] = {name = "Death Knight Rider of the Apocalypse 11.2 Class Set 2pc", additional_info = "[q]Sangre, Profano\n Ahora, Apocalipsis invoca a Melenablanca durante 10 s. No-muerte de Melenablanca inflige un 20% más de daño e infecta a 1 objetivo más cuando se propaga. Además, su Espiral de la muerte inflige un 35% más de daño.\n\nEscarcha\n Pilar de Escarcha ahora invoca a Aterratrols durante 10 s. Furia gélida de Aterratrols inflige un 20% más de daño, y su Asolar inflige un 15% más de daño."}
MultiLanguageSpellData['es'][1236356] = {name = "Death Knight Rider of the Apocalypse 11.2 Class Set 4pc", additional_info = "[q]Escarcha\n Al lanzar Asolar o Guadaña de Escarcha, ordenas a Aterratrols que lance su Asolar o Guadaña de Escarcha junto a ti con un 100% de efectividad. Tu Asolar inflige un 20% más de daño a los objetivos afectados por Furia gélida de Aterratrols.\n\nSangre, Profano\n Al lanzar Espiral de la muerte o Epidemia, ordenas a Melenablanca que lance su Espiral de la muerte o Epidemia junto a ti con un 125% de efectividad. Tu Espiral de la muerte inflige un 40% más de daño a los objetivos afectados por No-muerte de Melenablanca.\n\n(500ms de reutilización)"}
MultiLanguageSpellData['es'][1236358] = {name = "Demon Hunter Aldrachi Reaver 11.2 Class Set 2pc", additional_info = "[q]El daño de Guja de atracador aumenta un 50%, y el resto del daño únicamente físico, un 25%."}
MultiLanguageSpellData['es'][1236360] = {name = "Demon Hunter Aldrachi Reaver 11.2 Class Set 4pc", additional_info = "[q]Devastación\n Furia de los Aldrachi potencia más Danza de hojas cuando se lanza después de Golpe de caos, lo que aumenta los cortes a 12.\n\n Ahora, Marca de atracador se acumula hasta 2 veces y potencia más Golpe de caos cuando se lanza después de Danza de hojas, lo que aplica una acumulación más con un 100% de la duración normal.\n\nVenganza\n Furia de los Aldrachi potencia más Rajar alma cuando se lanza después de Hender, lo que aumenta los cortes a 12.\n\n Ahora, Marca de atracador se acumula hasta 2 veces y potencia más Hender cuando se lanza después de Rajar alma, lo que aplica una acumulación más con un 100% de la duración normal."}
MultiLanguageSpellData['es'][1236361] = {name = "Demon Hunter Fel-Scarred 11.2 Class Set 2pc", additional_info = "[q]Devastación\n Aura de inmolación inflige un 30% más de daño y aumenta un 20% el daño de Golpe de caos mientras está activa.\n\nVenganza\n Aura de inmolación inflige un 30% más de daño y aumenta un 20% el daño de Rajar alma mientras está activa."}
MultiLanguageSpellData['es'][1236362] = {name = "Demon Hunter Fel-Scarred 11.2 Class Set 4pc", additional_info = "[q]Devastación\n Ahora, al entrar en forma de demonio, se activa inmediatamente una Oleada demoníaca y se destruye un trozo de alma demoníaca que otorga un 20% más de daño durante 10 s.\n\nVenganza\n Ahora, al entrar en forma de demonio, se activa inmediatamente una Oleada demoníaca y se destruye un trozo de alma demoníaca que otorga un 20% más de daño durante 15 s.\n\n(100ms de reutilización)"}
MultiLanguageSpellData['es'][1236364] = {name = "Evoker Flameshaper 11.2 Class Set 2pc", additional_info = "[q]Envolver aviva tu Llama interior, lo que aumenta un 25% tu daño y tu sanación en el tiempo, además de aumentar un 50% tu probabilidad de obtener Explosión de esencia durante 12 s. Se acumula hasta 2 veces. Se pueden solapar varias aplicaciones."}
MultiLanguageSpellData['es'][1236365] = {name = "Evoker Flameshaper 11.2 Class Set 4pc", additional_info = "[q]Devastación\n Al consumir Explosión de esencia durante Llama interior, disparas una bomba de esencia a tu objetivo que inflige ([371% of Spell Power]) p. de daño Arcano a los enemigos cercanos. Este efecto se reduce al superar los 5 objetivos.\n\nPreservación, Aumento\n Al consumir Explosión de esencia durante Llama interior, disparas una bomba de esencia a tu objetivo que sana ([250% of Spell Power]) p. a los aliados cercanos. Este efecto se reduce al superar los 5 objetivos."}
MultiLanguageSpellData['es'][1236366] = {name = "Evoker Scalecommander 11.2 Class Set 2pc", additional_info = "[q]Aumento\n Al volar durante Aliento profundo y durante 20 s después, comandas un escuadrón de 2 dracthyr que atacará a tus objetivos con Desintegrar y Pira.\n\nDevastación, Preservación\n Al volar durante Aliento profundo y durante 10 s después, comandas un escuadrón de 2 dracthyr que atacará a tus objetivos con Desintegrar y Pira."}
MultiLanguageSpellData['es'][1236367] = {name = "Evoker Scalecommander 11.2 Class Set 4pc", additional_info = "[q]Devastación\n Mientras tu escuadrón esté activo, tu Desintegración en masa golpeará a un máximo de 2 objetivo más. Además, tu escuadrón te ayudará durante 5 s más.\n\nAumento\n Mientras tu escuadrón esté activo, tu Erupción en masa golpeará a un máximo de 2 objetivo más. Además, tu escuadrón te ayudará durante 10 s más.\n\nPreservación\n Mientras tu escuadrón esté activo, tu Erupción en masa golpeará a un máximo de 2 objetivo más. Además, tu escuadrón te ayudará durante 5 s más."}
MultiLanguageSpellData['es'][1236368] = {name = "Evoker Chronowarden 11.2 Class Set 2pc", additional_info = "[q]El tiempo de reutilización de Inclinar la balanza se reduce 60 s."}
MultiLanguageSpellData['es'][1236369] = {name = "Evoker Chronowarden 11.2 Class Set 4pc", additional_info = "[q]Ráfaga temporal hace que Cronollamas golpee a 2 objetivo más y repita un 15% más de daño o sanación, hasta un máximo de [(Poder con Hechizos * 4.5) * (1 + Versatilidad)]. Además, aumenta un 30% el daño y la sanación de tus facultades de esencia."}
MultiLanguageSpellData['es'][1236370] = {name = "Hunter Dark Ranger 11.2 Class Set 2pc", additional_info = "[q]Puntería, Supervivencia\n El daño de la flecha de Flecha negra aumenta un 10%, y el de Pólvora desoladora, un 20%. Se reduce 30 s el tiempo de reutilización de Disparo certero.\n\nBestias\n El daño de la flecha de Flecha negra aumenta un 10%, y el de Pólvora desoladora, un 20%. Se reduce 60 s el tiempo de reutilización de Llamada de lo salvaje."}
MultiLanguageSpellData['es'][1236371] = {name = "Hunter Dark Ranger 11.2 Class Set 4pc", additional_info = "[q]Bestias, Puntería, Supervivencia\n El daño de Flecha negra de Fuego devastador aumenta un 50%. Al consumir Arremetida mortal, hay un 50% de probabilidades de hacer que todas las trombas de flechas negras durante tu siguiente Fuego devastador disparen 1 flecha negra más."}
MultiLanguageSpellData['es'][1236372] = {name = "Hunter Pack Leader 11.2 Class Set 2pc", additional_info = "[q]Puntería, Supervivencia\n El daño de mascota aumenta un 15%, y el daño de bestias, un 15%. Al invocar una bestia, se obtiene un 6% de celeridad, maestría o probabilidad de golpe crítico dependiendo de la bestia invocada durante 8 s.\n\nBestias\n El daño de mascota aumenta un 5%, y el daño de bestias, un 15%. Al invocar una bestia, se obtiene un 6% de celeridad, maestría o probabilidad de golpe crítico dependiendo de la bestia invocada durante 8 s."}
MultiLanguageSpellData['es'][1236373] = {name = "Hunter Pack Leader 11.2 Class Set 4pc", additional_info = "[q]Al invocar una bestia estando bajo los efectos de Liderar desde el frente, provocas una estampida de la fauna cercana que cargará contra tu objetivo e infligirá [([300% of Attack Power]) * 9] p. de daño físico a hasta 8 enemigos durante 7 s."}
MultiLanguageSpellData['es'][1236374] = {name = "Hunter Sentinel 11.2 Class Set 2pc", additional_info = "[q]Bestias, Supervivencia\n Daño de Bomba de fuego salvaje aumentado un 10%. Cuando Tormenta lunar se desvanece, obtienes la Ayuda de Elune, lo que hace que, durante 2 usos de Bomba de fuego salvaje, esta facultad inflija daño Arcano y su daño inicial aumente un 150%.\n\nPuntería\n Daño de Fuego rápido aumentado un 25%. Cuando Tormenta lunar se desvanece, obtienes la Ayuda de Elune, lo que hace que, durante 2 usos de Disparo de puntería, esta facultad inflija daño Arcano y su daño aumente un 10%."}
MultiLanguageSpellData['es'][1236375] = {name = "Hunter Sentinel 11.2 Class Set 4pc", additional_info = "[q]Puntería\n El daño de Centinela aumenta un 18%. Ahora, Ayuda de Elune está activa mientras dura Tormenta lunar con un 100% de efectividad.\n\nBestias, Supervivencia\n El daño de Centinela aumenta un 20%. Ahora, Ayuda de Elune está activa mientras dura Tormenta lunar con un 100% de efectividad."}
MultiLanguageSpellData['es'][1236376] = {name = "Maraña de alma", additional_info = nil}
MultiLanguageSpellData['es'][1236377] = {name = "Monk Master of Harmony 11.2 Class Set 2pc", additional_info = "[q]Maestro cervecero\n Al obtener vitalidad, aumentas de manera creciente las probabilidades de que tu siguiente Palma del tigre desate una Oleada armónica que infligirá [180 * ([400% of Spell Power]) / 100] p. de daño de Naturaleza a dividir entre tu objetivo y otros enemigos cercanos, y sanará [20 * ([500% of Spell Power]) / 100] p. a un máximo de 5 aliados heridos.\n\nViajero del viento, Tejedor de niebla\n Al obtener vitalidad, aumentas de manera creciente las probabilidades de que tu siguiente Palma del tigre desate una Oleada armónica que infligirá [20 * ([400% of Spell Power]) / 100] p. de daño de Naturaleza a dividir entre tu objetivo y otros enemigos cercanos, y sanará [90 * ([500% of Spell Power]) / 100] p. a un máximo de 5 aliados heridos."}
MultiLanguageSpellData['es'][1236378] = {name = "Monk Master of Harmony 11.2 Class Set 4pc", additional_info = "[q]Viajero del viento, Tejedor de niebla\n Al lanzar Té de enfoque del trueno, garantizas que, durante 2 lanzamiento de Palma del tigre, se active una Oleada armónica.\n\nMaestro cervecero\n Al lanzar , garantizas que, durante 2 lanzamiento de Palma del tigre, se active una Oleada armónica."}
MultiLanguageSpellData['es'][1236379] = {name = "Monk Shado-Pan 11.2 Class Set 2pc", additional_info = "[q]Maestro cervecero\n Aluviones de golpes inflige un 10% más de daño. Además, al activar Armas de orden, obtienes al instante 10 acumulaciones de Aluviones de golpes que se activan en tu siguiente ataque con un 70% de efectividad.\n\nViajero del viento, Tejedor de niebla\n Aluviones de golpes inflige un 20% más de daño. Además, al activar Tormenta, Tierra y Fuego, obtienes al instante 10 acumulaciones de Aluviones de golpes que se activan en tu siguiente ataque con un 70% de efectividad."}
MultiLanguageSpellData['es'][1236380] = {name = "Monk Shado-Pan 11.2 Class Set 4pc", additional_info = "[q]Maestro cervecero, Tejedor de niebla\n La generación de cargas de Aluvión aumenta un 50%, y Aluviones de golpes se activa cada vez que gastas 150 p. de energía durante Armas de orden.\n\nViajero del viento\n La generación de cargas de Aluvión aumenta un 50%, y Aluviones de golpes se activa cada vez que gastas 150 p. de energía durante Tormenta, Tierra y Fuego."}
MultiLanguageSpellData['es'][1236381] = {name = "Monk Conduit of the Celestials 11.2 Class Set 2pc", additional_info = "[q]Viajero del viento\n Corazón del dragón de jade se activa durante 4 s con un 100% de efectividad después de lanzar Vientos cortantes.\n\nMaestro cervecero, Tejedor de niebla\n Corazón del dragón de jade se activa durante 8 s con un 100% de efectividad después de lanzar Té de enfoque del trueno.\n\n(1s de reutilización)"}
MultiLanguageSpellData['es'][1236382] = {name = "Monk Conduit of the Celestials 11.2 Class Set 4pc", additional_info = "[q]Corazón del dragón de jade aumenta un 10% tu celeridad mientras está activo y durante 4 s después."}
MultiLanguageSpellData['es'][1236383] = {name = "Paladin Herald of the Sun 11.2 Class Set 2pc", additional_info = "Requiere Paladín\n[q]Reprensión\n La sanación y el daño de Albaluz aumentan un 30%, y obtienes Cólera solar después de que Cólera vengativa se desvanezca, lo que provoca que el efecto de Avatar del sol dure [10][10] s más.\n\nProtección\n La sanación y el daño de Albaluz aumentan un 30%, y obtienes Cólera solar después de que Cólera vengativa se desvanezca, lo que provoca que el efecto de Avatar del sol dure [10][10] s más.\n\nSagrado (Cólera vengativa)\n La sanación y el daño de Albaluz aumentan un 60%, y obtienes Cólera solar después de que Cólera vengativa se desvanezca, lo que provoca que el efecto de Avatar del sol dure 10[10][10] s más."}
MultiLanguageSpellData['es'][1236384] = {name = "Paladin Herald of the Sun 11.2 Class Set 4pc", additional_info = "Requiere Paladín\n[q]Reprensión\n Cólera solar aumenta un 15% la efectividad de tus facultades que consumen poder sagrado y te otorga [2][2] Albaluz.\n\nProtección\n Cólera solar aumenta un 15% la efectividad de tus facultades que consumen poder sagrado y te otorga [2][2] Albaluz.\n\nSagrado (Cólera vengativa)\n Cólera solar aumenta un 30% la efectividad de tus facultades que consumen poder sagrado y te otorga 2[2][2] Albaluz."}
MultiLanguageSpellData['es'][1236385] = {name = "Ametrallamiento de alma", additional_info = nil}
MultiLanguageSpellData['es'][1236389] = {name = "Paladin Lightsmith 11.2 Class Set 2pc", additional_info = "Requiere Paladín\n[q]Protección\n El daño de Martillo y yunque aumenta un 15%, y también puede activarlo con un 40% de efectividad.\n\nReprensión\n La sanación de Martillo y yunque aumenta un 15%, y Golpe de cruzado también puede activarlo con un 40% de efectividad.\n\nSagrado\n La sanación de Martillo y yunque aumenta un 15%, y Golpe de cruzado también puede activarlo con un 75% de efectividad.\n\n(750ms de reutilización)"}
MultiLanguageSpellData['es'][1236390] = {name = "Paladin Lightsmith 11.2 Class Set 4pc", additional_info = "Requiere Paladín\n[q]Martillo y yunque también otorga una acumulación de Obra maestra, lo que hace que tu siguiente Armamento sacro lance una versión inferior del hechizo a un aliado cercano por cada acumulación."}
MultiLanguageSpellData['es'][1236391] = {name = "Paladin Templar 11.2 Class Set 2pc", additional_info = "Requiere Paladín\n[q]Tu Martillo empíreo inflige un 20% más de daño crítico, y sus golpes críticos tienen un 50% de probabilidades de otorgar una acumulación adicional de Liberación de Luz.\n(Probabilidad de que accione: 50%)"}
MultiLanguageSpellData['es'][1236392] = {name = "Paladin Templar 11.2 Class Set 4pc", additional_info = "Requiere Paladín\n[q]Reprensión\n Martillo de Luz inflige un 35% más de daño a su objetivo principal, golpea a 3 objetivos secundarios más y ahora puede lanzarse 1 vez más después de Estela de cenizas.\n\nSagrado, Protección\n Martillo de Luz inflige un 35% más de daño a su objetivo principal, golpea a 3 objetivos secundarios más y ahora puede lanzarse 1 vez más después de Ojo de Tyr."}
MultiLanguageSpellData['es'][1236394] = {name = "Priest Oracle 11.2 Class Set 2pc", additional_info = "[q]Sagrado, Sombra\nAl lanzar Rezo de alivio, tu objetivo se sana ([1400% of Spell Power]) p.\n\nDisciplina\n La primera descarga de cada lanzamiento de Penitencia inflige daño o sana un 200% más."}
MultiLanguageSpellData['es'][1236395] = {name = "Priest Oracle 11.2 Class Set 4pc", additional_info = "[q]Al lanzar Premonición de piedad o Premonición de consuelo, otorgas 2 acumulación de Premonición de perspicacia con un 100% de efectividad. Al consumir una acumulación de Premonición de perspicacia, aumentas un 1.0% tu celeridad durante 10 s. Se pueden solapar varias aplicaciones."}
MultiLanguageSpellData['es'][1236396] = {name = "Priest Voidweaver 11.2 Class Set 2pc", additional_info = "[q]Sagrado\n El daño de Explosión del Vacío aumenta un 30%, y el tiempo de lanzamiento de Explosión del Vacío se reduce un 20%.\n\nSombra\n El daño de Explosión del Vacío aumenta un 30%, y el tiempo de lanzamiento de Explosión del Vacío se reduce un 20%.El tiempo de reutilización de Explosión del Vacío se reduce un 50%.\n\nDisciplina\n El daño de Explosión del Vacío y Penitencia aumenta un 30%, y el tiempo de lanzamiento de Explosión del Vacío se reduce un 20%."}
MultiLanguageSpellData['es'][1236397] = {name = "Priest Voidweaver 11.2 Class Set 4pc", additional_info = "[q]Disciplina\n Ahora, Explosión del Vacío también hace que la falla entrópica crezca, Vacío en colapso aumente un 10% el daño de la falla entrópica y el daño de tu siguiente Explosión mental aumente un 200% según el tamaño de la falla entrópica cuando colapse.\n\nSagrado, Sombra\n Ahora, Explosión del Vacío también hace que la falla entrópica crezca, Vacío en colapso aumente un 10% el daño de la falla entrópica y el daño de tu siguiente Torrente del Vacío aumente un 200% según el tamaño de la falla entrópica cuando colapse."}
MultiLanguageSpellData['es'][1236398] = {name = "Priest Archon 11.2 Class Set 2pc", additional_info = "[q]Sombra\n Los halos generan 10 p. más de demencia durante 5 s, y la energía resonante aumenta un 5.0% el daño de tu Peste devoradora.\n\nDisciplina, Sagrado\n Los halos reducen 5 s el tiempo de reutilización de tu Palabra sagrada: serenidad y Palabra sagrada: santificar, y la energía resonante aumenta un 5.0% la sanación de tus Palabras sagradas."}
MultiLanguageSpellData['es'][1236399] = {name = "Priest Archon 11.2 Class Set 4pc", additional_info = "[q]Sagrado\n Mientras Oleada de poder está activa, por cada 2 lanzamientos de Palabra sagrada: serenidad o Palabra sagrada: santificar se añade otro halo al efecto con un 100% de efectividad, hasta un máximo de 2 veces.\n\nDisciplina, Sombra\n Mientras Oleada de poder está activa, por cada 2 lanzamientos de Peste devoradora se añade otro halo al efecto con un 100% de efectividad, hasta un máximo de 2 veces."}
MultiLanguageSpellData['es'][1236400] = {name = "Rogue Deathstalker 11.2 Class Set 2pc", additional_info = "[q]Asesinato\n Puyazo aumenta un 60% la efectividad de los efectos de daño y el bonus de daño de Mortacechador.\n\nForajido, Sutileza\n Símbolos de la Muerte aumenta un 40% la efectividad de los efectos de daño y el bonus de daño de Mortacechador."}
MultiLanguageSpellData['es'][1236401] = {name = "Rogue Deathstalker 11.2 Class Set 4pc", additional_info = "[q]Asesinato\n Puyazo tiene 3 s más de duración y consume una aplicación de tu Marca de mortacechador activa al usarse.\n\nForajido, Sutileza\n Símbolos de la Muerte tiene 3 s más de duración y consume una aplicación de tu Marca de mortacechador activa al usarse."}
MultiLanguageSpellData['es'][1236402] = {name = "Rogue Fatebound 11.2 Class Set 2pc", additional_info = "[q]Forajido\n Golpe fantasmal inflige un 50% más de daño y tiene 4 s más de duración.\n\n Ahora, Al límite lanza una moneda vinculada al destino más, y su efecto se activa al usar Golpe fantasmal.\n\nAsesinato, Sutileza\n Perdición de Reyes inflige un 10% más de daño y tiene 4 s más de duración.\n\n Ahora, Al límite lanza una moneda vinculada al destino más, y su efecto se activa al usar Perdición de Reyes."}
MultiLanguageSpellData['es'][1236403] = {name = "Rogue Fatebound 11.2 Class Set 4pc", additional_info = "[q]Asesinato, Sutileza\n El hecho de tener una moneda vinculada al destino afortunada reduce 30.0 s el tiempo de reutilización de Marca de muerte y 15.0 s el de Perdición de Reyes.\n\nForajido\n El hecho de tener una moneda vinculada al destino afortunada reduce 30.0 s el tiempo de reutilización de Subidón de adrenalina y 15.0 s el de Golpe fantasmal."}
MultiLanguageSpellData['es'][1236404] = {name = "Rogue Trickster 11.2 Class Set 2pc", additional_info = "[q]Hoja oculta inflige un 35% más de daño y tiene un 35% de probabilidades de golpear dos veces."}
MultiLanguageSpellData['es'][1236405] = {name = "Rogue Trickster 11.2 Class Set 4pc", additional_info = "[q]Ahora se puede activar una segunda vez Golpe de gracia en un intervalo de 5 s para infligir un 150% del daño normal."}
MultiLanguageSpellData['es'][1236406] = {name = "Shaman Farseer 11.2 Class Set 2pc", additional_info = "[q]Presteza ancestral invoca a un ancestro potenciado durante 15 s con un 10% más de daño y sanación."}
MultiLanguageSpellData['es'][1236407] = {name = "Shaman Farseer 11.2 Class Set 4pc", additional_info = "[q]Elemental, Mejora\n Presteza ancestral aumenta un 25% el daño y la sanación de tus hechizos, y reduce un 25% su coste de maná, además de aumentar un 50% el índice de recarga de Ráfaga de lava durante 8 s.\n\nRestauración\n Presteza ancestral aumenta un 25% el daño y la sanación de tus hechizos, y reduce un 25% su coste de maná, además de aumentar un 50% el índice de recarga de Ráfaga de lava y Mareas vivas durante 8 s."}
MultiLanguageSpellData['es'][1236408] = {name = "Shaman Stormbringer 11.2 Class Set 2pc", additional_info = "[q]Mejora, Restauración\n Ascensión tiene un 100% de probabilidades de otorgar una carga de Tempestad. Además, por cada 8 Tormentas del despertar se activa Ascensión durante 6.0 s.\n\nElemental\n Ascensión tiene un 100% de probabilidades de otorgar una carga de Tempestad. Además, por cada 9 Tormentas del despertar se activa Ascensión durante 6.0 s.\n\n(100ms de reutilización)"}
MultiLanguageSpellData['es'][1236409] = {name = "Shaman Stormbringer 11.2 Class Set 4pc", additional_info = "[q]Elemental, Restauración\n El daño de Naturaleza aumenta un 3.0%, y Ascensión potencia tus siguientes 2 Tempestades para formar una tormenta en el cielo que inflige ([960% of Spell Power]) p. de daño de Naturaleza a su objetivo principal y daño reducido a los enemigos cercanos tras 1.5 s.\n\nMejora\n El daño de Naturaleza aumenta un 5.0%, y Ascensión potencia tus siguientes 2 Tempestades para formar una tormenta en el cielo que inflige ([400% of Attack Power]) p. de daño de Naturaleza a su objetivo principal y daño reducido a los enemigos cercanos tras 1.5 s.\n\n(100ms de reutilización)"}
MultiLanguageSpellData['es'][1236410] = {name = "Shaman Totemic 11.2 Class Set 2pc", additional_info = "[q]Elemental, Restauración\n Tras consumir todas las motas de Torbellino de elementos, lanzas Chaparrón con un 200% de efectividad en la ubicación de tu tótem emergente.\n\nMejora\n Tras consumir todas las motas de Torbellino de elementos, tu tótem emergente lanza Tormenta primigenia con un 200% de efectividad en su ubicación."}
MultiLanguageSpellData['es'][1236411] = {name = "Shaman Totemic 11.2 Class Set 4pc", additional_info = "[q]Elemental, Restauración\n Tras lanzar Chaparrón, tu siguiente Sanación en cadena, Ola de sanación u Oleada de sanación se vuelve a lanzar con un 150% de efectividad.\n\nMejora\n Tras lanzar Tormenta primigenia, tu siguiente Latigazo de lava o Nova de Fuego se vuelve a lanzar con un 150% de efectividad.\n\n(500ms de reutilización)"}
MultiLanguageSpellData['es'][1236413] = {name = "Warlock Hellcaller 11.2 Class Set 2pc", additional_info = "[q]Demonología, Destrucción\n Marca de Xavius aumenta un 3% más el daño de Alma ennegrecida por cada acumulación. Malevolencia aumenta en 2 las acumulaciones de Marchitar.\n\nAflicción\n Marca de Xavius aumenta un 6% más el daño de Alma ennegrecida por cada acumulación. Malevolencia aumenta en 2 las acumulaciones de Marchitar."}
MultiLanguageSpellData['es'][1236414] = {name = "Warlock Hellcaller 11.2 Class Set 4pc", additional_info = "[q]Aflicción\n Al lanzar Malevolencia, otorgas 2 acumulaciones de Crescendo atormentado y evitas que Alma ennegrecida consuma acumulaciones mientras infliges daño un 25% más rápido durante 8 s.\n\nDemonología, Destrucción\n Al lanzar Malevolencia, otorgas 2 acumulaciones de Explosión de humo y evitas que Alma ennegrecida consuma acumulaciones mientras infliges daño un 15% más rápido durante 8 s."}
MultiLanguageSpellData['es'][1236415] = {name = "Warlock Soul Harvester 11.2 Class Set 2pc", additional_info = "[q]Sombra de muerte lanza a tu alma demoníaca contra tu objetivo actual durante 9 s, lo que inflige ([279.306% of Spell Power]) p. de daño de las Sombras y ([186.209% of Spell Power]) p. de daño de las Sombras a los enemigos en un radio de 10 m con cada barrido."}
MultiLanguageSpellData['es'][1236416] = {name = "Warlock Soul Harvester 11.2 Class Set 4pc", additional_info = "[q]El daño de Alma demoníaca aumenta un 45%, y el de Siega perversa, un 45%. Tu alma demoníaca genera 1 fragmento de alma cada 3 s mientras ataca a los enemigos."}
MultiLanguageSpellData['es'][1236417] = {name = "Warlock Diabolist 11.2 Class Set 2pc", additional_info = "[q]Aflicción, Destrucción\n Al lanzar Descarga de caos, Lluvia de Fuego o Quemadura de las Sombras se invoca un óculo demoníaco, hasta un máximo de 3. Al consumir Arte demoníaco, lanzas tus óculos demoníacos contra tu objetivo actual para que exploten. Esta explosión inflige ([502.813% of Spell Power]) p. de daño de Fuego y ([335.172% of Spell Power]) p. de daño de Fuego a los enemigos en un radio de 10 m.\n\nDemonología\n Al lanzar Mano de Gul'dan al máximo de poder se invoca un óculo demoníaco, hasta un máximo de 3. Al consumir Arte demoníaco, lanzas tus óculos demoníacos contra tu objetivo actual para que exploten. Esta explosión inflige ([502.813% of Spell Power]) p. de daño de Fuego y ([335.172% of Spell Power]) p. de daño de Fuego a los enemigos en un radio de 10 m."}
MultiLanguageSpellData['es'][1236418] = {name = "Warlock Diabolist 11.2 Class Set 4pc", additional_info = "[q]Los óculos demoníacos analizan la batalla mientras están activos y te envían información cuando explotan, lo que aumenta un 2% tu intelecto durante 10 s."}
MultiLanguageSpellData['es'][1236419] = {name = "Warrior Colossus 11.2 Class Set 2pc", additional_info = "[q]El daño de Demoler aumenta un 20%, y el daño crítico de tus facultades aumenta hasta un 20% contra objetivos afectados por tu Demoler durante 10 s según el número de acumulaciones de Poderío colosal consumidas."}
MultiLanguageSpellData['es'][1236420] = {name = "Warrior Colossus 11.2 Class Set 4pc", additional_info = "[q]Furia, Protección\n Demoler aumenta un 100% la probabilidad de golpe crítico de 1 tu siguiente Embate con escudo. Los golpes críticos de Embate con escudo aumentan un 80% el daño de tu Desgarrar y Heridas profundas durante 8 s.\n\nArmas\n Demoler aumenta un 100% la probabilidad de golpe crítico de 1 tu siguiente Golpe mortal. Los golpes críticos de Golpe mortal aumentan un 80% el daño de tu Desgarrar y Heridas profundas durante 8 s."}
