MultiLanguageSpellData['es'][1236422] = {name = "Warrior Mountain Thane 11.2 Class Set 4pc", additional_info = "[q]Golpe ionizante inflige un 100% más de daño, y, cuando activas Golpe ionizante, obtienes una carga de Explosión de trueno. Además, tu siguiente Explosión de trueno inflige un 100% más de daño."}
