MultiLanguageSpellData['es'][1236703] = {name = "Tejido eterno", additional_info = "Hechizo de 5 seg\n[q]Al llegar a 100 p. de energía, la escriba de almas inicia un ritual de 24 s de duración que emite una serie de conos que infligen 7273348 p. de daño Arcano a los jugadores en su interior.\n\n Los destinos alcanzados aplican Destino herido a los jugadores vinculados."}
