MultiLanguageSpellData['es'][1236748] = {name = "Paladin Templar 11.2 Class Set 4pc Driver", additional_info = "Instante Requiere Paladín\n[q]Reprensión\n Martillo de Luz inflige un 0% más de daño a su objetivo principal, golpea a 0 objetivos secundarios más y ahora puede lanzarse 0 vez más después de Estela de cenizas.\n\nSagrado, Protección\n Martillo de Luz inflige un 0% más de daño a su objetivo principal, golpea a 0 objetivos secundarios más y ahora puede lanzarse 0 vez más después de Ojo de Tyr."}
MultiLanguageSpellData['es'][1236759] = {name = "Ráfaga de sobreinfusión", additional_info = "Rango ilimitado\nInstante\n[q]Loom'ithar inflige 266671 p. de daño Arcano a todos los jugadores cada 0.5 s durante 8 s mientras absorbe energía Arcana. Tras esto, desata la energía en una inmensa explosión que inflige 129345416 p. de daño Arcano a los jugadores en un radio de 45 m."}
MultiLanguageSpellData['es'][1236761] = {name = "Devorar", additional_info = "Alcance de 150 m\nInstante\n[q]Al llegar a 100 p. de energía, Azhiccar inhala e intenta consumir a todos los jugadores y criaturas de la arena durante 18 s. Todos los jugadores reciben 606112 p. de daño de las Sombras durante 1 s.\n\n Cada vez que Azhiccar logra consumir a una criatura viva o jugador, se da un Festín ."}
