MultiLanguageSpellData['es'][1236784] = {name = "Nexo quebradizo", additional_info = "Instante\n[q]Un muro cristalino de energía del Vacío que explota al impactar con un jugador afectado por Revestimiento de cristal . La explosión lanza Metralla del Nexo y aplica Laceraciones de cristal a todos los jugadores."}
MultiLanguageSpellData['es'][1236785] = {name = "Nexo imbuido de Vacío", additional_info = "Instante\n[q]Un muro cristalino de energía del Vacío que explota al impactar con un jugador afectado por Revestimiento de cristal . La explosión lanza Metralla del Nexo y aplica Metralla del Nexo a varios jugadores."}
MultiLanguageSpellData['es'][1236792] = {name = "Bomba de esencia", additional_info = "Alcance de 30 m\nInstante\n[q]Devastación\nAl consumir Explosión de esencia durante Llama interior, disparas una bomba de esencia a tu objetivo que inflige ([371% of Spell Power]) p. de daño Arcano a los enemigos cercanos. Este efecto se reduce al superar los 5 objetivos.\n\nPreservación, Aumento\nAl consumir Explosión de esencia durante Llama interior, disparas una bomba de esencia a tu objetivo que sana ([250% of Spell Power]) p. a los aliados cercanos. Este efecto se reduce al superar los 5 objetivos."}
MultiLanguageSpellData['es'][1236803] = {name = "Bomba de esencia", additional_info = "Alcance de 30 m\nInstante\n[q]Devastación\nAl consumir Explosión de esencia durante Llama interior, disparas una bomba de esencia a tu objetivo que inflige ([371% of Spell Power]) p. de daño Arcano a los enemigos cercanos. Este efecto se reduce al superar los 5 objetivos.\n\nPreservación, Aumento\nAl consumir Explosión de esencia durante Llama interior, disparas una bomba de esencia a tu objetivo que sana ([250% of Spell Power]) p. a los aliados cercanos. Este efecto se reduce al superar los 5 objetivos."}
MultiLanguageSpellData['es'][1236807] = {name = "Favor de la dríade", additional_info = "Instante\n[q]Restauración\nCuando tu Dríade se desvanece, tus siguientes 2Alivio presto sanan una cantidad equivalente al 5% de tu sanación realizada mientras estaba activa y salpican con un 25% de su sanación a aliados cercanos. Este efecto se reduce a partir de 5 objetivos.\n\nEquilibrio, Feral, Guardián\nCuando tu Dríade se desvanece, tus siguientes 2Oleada de estrellas infligen una cantidad equivalente al 3% de tu daño infligido mientras estaba activa y salpican con un 10% de su daño a enemigos cercanos. Este efecto se reduce a partir de 5 objetivos."}
MultiLanguageSpellData['es'][1236822] = {name = "Ímpetu de sangre", additional_info = "Instante\n[q]Profano\nInfligir pesar causa un 30% más de daño, y Golpe vampírico aumenta un 20% el daño de tu necrófago durante 8 s. Se pueden solapar varias aplicaciones.\n\nSangre, Escarcha\nInfligir pesar causa un 50% más de daño, y Golpe vampírico aumenta un 20% el daño de tu Arma de runa danzante durante 8 s. Se pueden solapar varias aplicaciones."}
MultiLanguageSpellData['es'][1236824] = {name = "Núcleo potenciado", additional_info = "Alcance de 300 m\nInstante\n[q]El núcleo del taumaturgo lo protege del daño recibido. Cuando se destruya el núcleo, este explotará e infligirá 34853 p. de daño Cósmico."}
