MultiLanguageSpellData['es'][1236937] = {name = "Corriente eléctrica", additional_info = "Instante\n[q]Obtienes Corriente eléctrica al entrar en combate, lo que aumenta 10 p. tu maestría cada 2 s hasta un máximo de (12 * 10 ) p. tras 24 s. Tras esto, volverá a empezar desde el principio."}
