MultiLanguageSpellData['es'][1236942] = {name = "Martillo divino", additional_info = "Rango ilimitado\nInstante Requiere Paladín\n[q]A tu alrededor giran unos martillos divinos que golpean e infligen [ Cruzada ardiente : [([39.984% of Attack Power])% * 1.05] p. de daño Radiante / ([39.984% of Attack Power])% p. de daño Sagrado] cada 2 s. durante 10 s.\n\n Mientras está activo, cada Poder sagrado consumido aumenta 0.3 s la duración de Martillo divino. Inflige daño reducido si golpea a más de 8 objetivos."}
MultiLanguageSpellData['es'][1236943] = {name = "Aliento profundo", additional_info = "Alcance de 100 m\n{Instante} {2 min de reutilización}\n[q]Respiras hondo y vuelas hacia delante mientras escupes unas cenizas de magma que infligen ([331.43% of Spell Power]) p. de daño Volcánico a los enemigos a tu paso.\n\n Elimina todos los efectos de enraizamiento. Mientras estás volando, eres inmune a los efectos de reducción de movimiento y pérdida de control. [ Arenas del tiempo : Aumenta 5 s la duración de los efectos activos de tu Poderío de ébano ]"}
