MultiLanguageSpellData['es'][1236971] = {name = "Granada de alteración", additional_info = "Alcance de 30 m\nInstante\n[q]Lanzas una Granada de alteración a un objetivo, que queda desorientado durante 4 s."}
MultiLanguageSpellData['es'][1236972] = {name = "Cólera solar", additional_info = "Instante Requiere Paladín\n[q]Sagrado (Cólera vengativa)\nLa sanación y el daño de Albaluz aumentan un 30%, y obtienes Cólera solar después de que Cólera vengativa se desvanezca, lo que provoca que el efecto de Avatar del sol dure 10[10][10] s más.\n\nReprensión\nLa sanación y el daño de Albaluz aumentan un 30%, y obtienes Cólera solar después de que Cólera vengativa se desvanezca, lo que provoca que el efecto de Avatar del sol dure [10][10] s más.\n\nProtección\nLa sanación y el daño de Albaluz aumentan un 30%, y obtienes Cólera solar después de que Cólera vengativa se desvanezca, lo que provoca que el efecto de Avatar del sol dure [10][10] s más."}
MultiLanguageSpellData['es'][1236973] = {name = "Tormento emergente", additional_info = "Alcance de 300 mHechizo de 3.5 seg 2 seg de reutilización\n[q]El lord chambelán emite una energía siniestra desde sí mismo y todas las estatuas de piedra del pecado que inflige 8485573 p. de daño de las Sombras a los jugadores en un radio de 10 m."}
MultiLanguageSpellData['es'][1236974] = {name = "Chispa vibrante", additional_info = "Rango ilimitado\nInstante\n[q]Existe la posibilidad de que tus sanaciones suelten una chispa que saltará al objetivo con menor salud en un radio de 40 m y le sanará 1766 p."}
MultiLanguageSpellData['es'][1236975] = {name = "Carcaj contagiado", additional_info = "Instante\n[q]Bestias, Puntería, Supervivencia\nEl daño de Flecha negra de Fuego devastador aumenta un 50%. Al consumir Arremetida mortal, hay un 50% de probabilidades de hacer que todas las trombas de flechas negras durante tu siguiente Fuego devastador disparen 1 flecha negra más."}
