MultiLanguageSpellData['es'][1236981] = {name = "Granada de alteración", additional_info = "Alcance de 30 m\nInstante\n[q]Lanzas una Granada de alteración a una ubicación que desorienta a los jugadores y criaturas en un radio de 0 m de la detonación durante 30 s."}
