MultiLanguageSpellData['es'][1236989] = {name = "Recolectar luz de luna", additional_info = "Instante\n[q]Equilibrio\nAl impactar, las Oleadas de estrellas lanzadas por Fuego estelar se dividen entre un máximo de 3 objetivos más con un 40% de efectividad y otorgan una acumulación de Recolectar luz de luna. Al lanzar Furia de Elune o Luna llena, se consume Recolectar luz de luna para aumentar un 4% tu daño por cada acumulación durante 12 s.\n\nFeral, Guardián, Restauración\nAl impactar, las Oleadas de estrellas lanzadas por Vapulear se dividen entre un máximo de 3 objetivos más con un 20% de efectividad y otorgan una acumulación de Recolectar luz de luna. Al lanzar Haz lunar, se consume Recolectar luz de luna para aumentar un 4% tu daño por cada acumulación durante 12 s."}
MultiLanguageSpellData['es'][1236990] = {name = "Difusión de luz de luna", additional_info = "Instante\n[q]Equilibrio\nAl impactar, las Oleadas de estrellas lanzadas por Fuego estelar se dividen entre un máximo de 3 objetivos más con un 40% de efectividad y otorgan una acumulación de Recolectar luz de luna. Al lanzar Furia de Elune o Luna llena, se consume Recolectar luz de luna para aumentar un 4% tu daño por cada acumulación durante 12 s.\n\nFeral, Guardián, Restauración\nAl impactar, las Oleadas de estrellas lanzadas por Vapulear se dividen entre un máximo de 3 objetivos más con un 20% de efectividad y otorgan una acumulación de Recolectar luz de luna. Al lanzar Haz lunar, se consume Recolectar luz de luna para aumentar un 4% tu daño por cada acumulación durante 12 s."}
MultiLanguageSpellData['es'][1236991] = {name = "Vacío devorador", additional_info = "Alcance de 100 m\nInstante\n[q]Al recibir daño, hay una probabilidad elevada de que devores la esencia de los enemigos cercanos para infligir 2116 p. de daño de las Sombras a dividir entre ellos y sanarte un 150% del daño infligido.\n\n El daño letal que no supere 18656 p. te restaura con un 20% de salud y te reconstituye como Vacío inestable durante 6 s. Supera el 50% de salud para estabilizarte y evitar la muerte. Este efecto puede ocurrir una vez cada 8 min. El núcleo no puede infligir daño mientras se recarga."}
MultiLanguageSpellData['es'][1236992] = {name = "Death Knight Deathbringer 11.2 Class Set 4pc", additional_info = nil}
MultiLanguageSpellData['es'][1236993] = {name = "Escudo de energía", additional_info = "Instante\n[q]Cuando recibas daño, existe la posibilidad de que obtengas un escudo de energía de los titanes, que evitará hasta 3662 p. de daño durante 10 s. Cuando se agote el escudo, infligirá el equivalente a un 30% de la absorción restante como daño Arcano a dividir entre los enemigos en un radio de 8 m."}
MultiLanguageSpellData['es'][1236996] = {name = "Alma potenciada", additional_info = "Instante\n[q]Sangre, Escarcha, Profano\nExterminar inflige un 20% más de daño y Marca de segador se puede acumular hasta 15 veces más. Tras explotar, Marca de segador aumenta un 10% tu probabilidad de golpe crítico durante 8 s."}
MultiLanguageSpellData['es'][1237011] = {name = "Ola de energía", additional_info = "Rango ilimitado\nInstante\n[q]Cuando recibas daño, existe la posibilidad de que obtengas un escudo de energía de los titanes, que evitará hasta 3662 p. de daño durante 10 s. Cuando se agote el escudo, infligirá el equivalente a un 30% de la absorción restante como daño Arcano a dividir entre los enemigos en un radio de 8 m."}
MultiLanguageSpellData['es'][1237032] = {name = "Arma de runa danzante", additional_info = "Alcance de 30 m\nInstante\nRequiere Arma cuerpo a cuerpo\n[q]Invoca 1 copia extra de Arma de runa danzante y aumenta 6 s su duración."}
MultiLanguageSpellData['es'][1237033] = {name = "Relámpago cargado", additional_info = "Rango ilimitado\nInstante\n[q]Existe la posibilidad de que tus hechizos y ataques disparen un relámpago cargado contra tu objetivo que infligirá 1206 p. de daño de Naturaleza a dividir entre los objetivos en un radio de 8 m."}
MultiLanguageSpellData['es'][1237036] = {name = "Comandar escuadrón", additional_info = "Alcance de 40 m\nInstante\n[q]Al usar Aliento profundo y durante hasta que se cancele después, comandas un escuadrón de 2 dracthyr que atacará a tus objetivos con Desintegrar y Ataque azur."}
