MultiLanguageSpellData['es'][1237067] = {name = "La caza", additional_info = "Rango ilimitado\nInstante\n[q]Velaryn marca a un jugador como presa y luego carga hacia él y le inflige 63242239 p. de daño de Caos. El efecto se reduce por cada jugador que se encuentre en el camino de La caza .\n\n Velaryn también golpea a los jugadores que se encuentren en el camino e inflige 9486336 p. de daño de Caos a los que estén en un radio de 3 m de cada jugador golpeado."}
MultiLanguageSpellData['es'][1237068] = {name = "Aliento de dimensión", additional_info = "Rango ilimitado\nHechizo de 2 seg\n[q]Durante 4 s , el alavacío lanza un rayo galáctico desde sus mandíbulas que inflige 5621532 p. de daño Cósmico a cualquier jugador afectado cada 0.3 s.\n\n Se abren varios portales que emiten su aliento en distintas direcciones."}
