MultiLanguageSpellData['es'][1237072] = {name = "Eyección inestable", additional_info = "Alcance de 150 m\nInstante\n[q]Escupe un torrente de energía devoradora que parasita 30 p. de salud a todos los jugadores en una línea de 50 m frente al taumaturgo. Las gotas infligen daño de las Sombras a los enemigos en un radio de 5 m y dejan tras de sí Babas devoradoras durante 25 s."}
