MultiLanguageSpellData['es'][1237146] = {name = "Charco de radiación", additional_info = "Alcance de 300 m\nInstante\n[q]El taumaturgo explota tras morir y deja tras de sí un charco de radiación que inflige 209120 p. de daño de Naturaleza cada 2 s a los jugadores que permanezcan en el charco."}
