MultiLanguageSpellData['es'][1237172] = {name = "Epidemia", additional_info = "Alcance de 40 m\nInstante\n[q]Provoca que cada una de tus Pestes virulentas se inflame e inflija ([26.3725% of Attack Power]) p. de daño de las Sombras al enemigo infectado y ([10.5491% of Attack Power]) p. de daño de las Sombras extra a todos los demás enemigos cerca de él."}
MultiLanguageSpellData['es'][1237173] = {name = "Atadura de infusión", additional_info = "Rango ilimitado\nInstante\n[q]Loom'ithar atrae a varios jugadores hacia su ubicación y los ata con unas hebras sedosas que infligen 452533 p. de daño Arcano cada segundo. Este efecto aumenta con el tiempo.\n\n Las hebras se rompen al estirarlas a 40 m, lo que crea una masa de Seda viviente en la ubicación del jugador."}
