MultiLanguageSpellData['es'][1237193] = {name = "Sed sobrecogedora", additional_info = "Rango ilimitado\nInstante\n[q]Adarus comparte el dolor de su sed insaciable con sus enemigos, lo que inflige 20 p. de daño Cósmico a todos los jugadores cada 1 s hasta que mueren."}
MultiLanguageSpellData['es'][1237195] = {name = "Carga enterrada", additional_info = "Alcance de 50 mHechizo de 4 seg 4 seg de reutilización\n[q]El taumaturgo avanza bajo tierra hacia su objetivo y, al hacerlo, inflige 4848899 p. de daño físico al objetivo y lanza por los aires a todos los jugadores en un radio de 10 m del objetivo tras emerger."}
