MultiLanguageSpellData['es'][1244405] = {name = "Célula de éter forjada con maná", additional_info = "Aproximadamente 2 activaciones por minuto\n[q]Existe la posibilidad de que tus facultades de sanación potencien la célula de éter, lo que aumentará 239 p. tu maestría, valor que se irá reduciendo ( 239 / 15) p. cada s. Dura 15 s."}
