MultiLanguageSpellData['es'][1244410] = {name = "Engullidor de esencia incorpóreo", additional_info = "Alcance de 50 m\n{Instante} {2 min de reutilización}\n[q]Arrancas la esencia mágica de tu objetivo y la consumes para infligir ( 612 * 1 ) p. de daño Arcano y obtener 247 p. de tu estadística secundaria más baja durante 20 s.\n\n Si el objetivo era un etéreo, en vez de eso, se aumenta tu estadística secundaria más alta."}
MultiLanguageSpellData['es'][1244414] = {name = "Ritual errático", additional_info = "Hechizo de 3 seg\n[q]El taumaturgo pide ayuda a K'aresh, lo que hace que unos espíritus etéreos se alejen de él formando patrones erráticos. Al moverse, los espíritus infligirán daño Arcano y aturdirán a los enemigos a su paso."}
