MultiLanguageSpellData['es'][1244417] = {name = "Duende de maná retorcido", additional_info = "Aproximadamente 10 activaciones por minuto\n[q]Existen muchas probabilidades de que tus hechizos y facultades de sanación invoquen un duende de maná retorcido para ayudarte en combate durante 10 s. El duende de maná retorcido sanará periódicamente a un aliado cercano aleatorio durante ( 515 * 1 ). El exceso de sanación se convierte en un escudo de absorción durante 5 s."}
