MultiLanguageSpellData['es'][1245197] = {name = "Destrero escalofriante del Jinete decapitado", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Surcando los cielos vas a volar, sobre tus enemigos vas a bajar, este corcel te llevará para su fin entregar.\"\nPuesto comercial"}
