MultiLanguageSpellData['es'][1245357] = {name = "Grifo de Norteron adornado", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Los jinetes de grifos ancianos y los altos chamanes de los Martillo Salvaje de Norteron adornaban sus grifos con piezas ornamentales cubiertas de plumas para mostrar su rango y su estatus.\"\nPuesto comercial"}
MultiLanguageSpellData['es'][1245358] = {name = "Grifo de nidal de alto chamán", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Los antiguos chamanes de los Martillo Salvaje que vieron a los grifos por primera vez creyeron que se trataban de espíritus elementales con forma mortal. Este encuentro marcaría al clan Martillo Salvaje durante generaciones.\"\nPuesto comercial"}
MultiLanguageSpellData['es'][1245359] = {name = "Grifo de las tierras altas de plumas de ceniza", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Según la leyenda de los Martillo Salvaje, se cree que las plumas naranjas de los grifos se deben a un rasgo hereditario que se remonta a sus ancestros elementales.\"\nPuesto comercial"}
MultiLanguageSpellData['es'][1245360] = {name = "Misil", additional_info = nil}
MultiLanguageSpellData['es'][1245361] = {name = "Guía del cielo alascuas", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a esta montura.\n[q]\"Desde las laderas de Khaz Modan seguimos sus alas prendidas con brasas; una antorcha rumbo al norte que atraviesa el oscuro cielo estival\". - Peregrinación del primer sabio salvaje\nPuesto comercial"}
MultiLanguageSpellData['es'][1245370] = {name = "Brizancada ornario", additional_info = "Hechizo de 1.5 seg\n[q]Invoca y retira a tu brizancada ornario.\n[q]\"Este talbuk es una montura de lo más testaruda aunque se haya acostumbrado a su jinete. Se aconseja prudencia.\"\nPuesto comercial"}
MultiLanguageSpellData['es'][1245376] = {name = "Cazador Arcano", additional_info = "Instante\n[q]Los golpes críticos de tus hechizos y facultades a distancia tienen muchas probabilidades de otorgarte Cazador Arcano hasta 5 veces, lo que aumentará 14 p. tu índice de golpe crítico por cada acumulación durante 8 s."}
MultiLanguageSpellData['es'][1245377] = {name = "Desplegar reubicadores", additional_info = "Instante\n[q]So'azmi despliega reubicadores por parejas para confundir a sus enemigos.\n Cuando un jugador toca un reubicador, se teletransporta de inmediato al reubicador vinculado correspondiente."}
MultiLanguageSpellData['es'][1245384] = {name = "Inferno vil", additional_info = "Rango ilimitado\nInstante\n[q]Velaryn envuelve la arena en unas llamas que infligen 843230 p. de daño de Fuego a todos los jugadores y 182700 p. de daño de Fuego más cada 0.5 s durante 15 s cuando se crea cada pilar del infierno. Este efecto se acumula.\n\n Las llamas infligen 8435981 p. de daño de Fuego cada 1 s a cualquier jugador que se adentre en la tormenta de fuego."}
MultiLanguageSpellData['es'][1245397] = {name = "Célula de éter forjada con maná", additional_info = "Instante\n[q]Existe la posibilidad de que tus facultades de sanación potencien la célula de éter, lo que aumentará 239 p. tu maestría, valor que se irá reduciendo ( 239 / 15) p. cada s. Dura 15 s."}
MultiLanguageSpellData['es'][1245422] = {name = "Tsunami Arcano", additional_info = "Rango ilimitado\nInstante\n[q]La Vinculadora de Almas golpea a su objetivo principal, que recibe 0 p. de daño Arcano cada 5.2 s durante hasta que se cancele. El jugador alcanzado aumenta un 40% el daño por Latigazo místico que recibe y un 15% el daño físico durante 45 s."}
MultiLanguageSpellData['es'][1245429] = {name = "Gasa de éter simbiótica", additional_info = nil}
MultiLanguageSpellData['es'][1245430] = {name = "Infusión Arcana", additional_info = "Instante\n[q]El taumaturgo imbuye de energía Arcana a los jugadores en un radio de 60 m e inflige 4918841 p. de daño Arcano y 1194576 p. de daño Arcano más cada 1 s durante 10 s.\n\n Además, los gusanos de seda nacientes en un radio de 60 m reciben Mordeduras Arcanas ."}
MultiLanguageSpellData['es'][1245431] = {name = "Gasa de éter simbiótica", additional_info = "Instante\n[q]Existe la posibilidad de que, al bloquear, parar o esquivar, se despierte la gasa, lo que hará que ataque e inflija 1430 p. de daño Arcano a dividir entre los enemigos cercanos mientras te protege de 8283 p. de daño durante 15 s."}
MultiLanguageSpellData['es'][1245440] = {name = "Piedra del Vacío k'areshi", additional_info = "Hechizo de 2.5 seg\n[q]Imbuye tu armadura de un tenue eco del Vacío que desbloquea efectos visuales extra para ciertas apariencias de conjuntos de clase de la Forja de Maná Omega.\n\n Este efecto se aplica a toda la banda guerrera."}
