MultiLanguageSpellData['es'][1245575] = {name = "Cólera del Devorador", additional_info = "Rango ilimitado\nHechizo de 12 seg\n[q]Adarus lanza unos orbes de Vacío voraz a varias ubicaciones que infligen 5621532 p. de daño Cósmico a todos los jugadores si no son interceptados.\n\n Adarus concentra su atención en los jugadores que hayan interceptado estos orbes y los ataca constantemente con Consumir , además de aumentar un 100% el daño físico que reciben.\n\n Al eliminarse, se transfiere Cólera del Devorador a un jugador cercano al tiempo que todos los jugadores reciben 2108075 p. de daño Cósmico."}
