MultiLanguageSpellData['es'][1248435] = {name = "Toque Arcano", additional_info = "Instante\n[q]Al destruir un cajón de seda armonizada, las manos del jugador se cubren durante 1 min de una energía Arcana que inflige 1 p. de daño Arcano cada 1 s.\n\n Mientras dure el efecto, existe la posibilidad de que el daño infligido por el jugador haga que el objetivo reciba 1 p. de daño Arcano periódico cada 1 s durante 10 s. Este efecto se acumula hasta un máximo de 10 veces.\n(Probabilidad de que accione: 25%, 3s de reutilización)"}
MultiLanguageSpellData['es'][1248447] = {name = "Toque Arcano", additional_info = "Rango ilimitado\nInstante\n[q]Al destruir un cajón de seda armonizada, las manos del jugador se cubren durante 1 min de una energía Arcana que inflige 1 p. de daño Arcano cada 1 s.\n\n Mientras dure el efecto, existe la posibilidad de que el daño infligido por el jugador haga que el objetivo reciba 1 p. de daño Arcano periódico cada 1 s durante 10 s. Este efecto se acumula hasta un máximo de 10 veces."}
