MultiLanguageSpellData['es'][1248603] = {name = "Asesinato múltiple", additional_info = "Alcance de 10 m\nInstante\nRequiere Arma cuerpo a cuerpo\n[q]Remate que desata una salva de disparos que infligen daño físico a enemigos aleatorios en un radio de 8 m. El número de golpes aumenta en función de los puntos de combo.\n\n Restaura 1 p. de combo cada 0.50 s.\n\n 1 punto: [(([225% of Attack Power]) + ([225% of Attack Power])) * 2] p. de daño durante 0.50 s.\n 2 puntos: [(([225% of Attack Power]) + ([225% of Attack Power])) * 3] p. de daño durante 1.00 s.\n 3 puntos: [(([225% of Attack Power]) + ([225% of Attack Power])) * 4] p. de daño durante 1.50 s.\n 4 puntos: [(([225% of Attack Power]) + ([225% of Attack Power])) * 5] p. de daño durante 2.00 s.\n 5 puntos: [(([225% of Attack Power]) + ([225% of Attack Power])) * 6] p. de daño durante 2.50 s.\n [  6 puntos: [(([225% of Attack Power]) + ([225% of Attack Power])) * 7] p. de daño durante 3.00 s.] [  7 puntos: [(([225% of Attack Power]) + ([225% of Attack Power])) * 8] p. de daño durante 3.50 s.]"}
