MultiLanguageSpellData['es'][1249462] = {name = "Trato: Cártel Zo", additional_info = "Instante\n[q]Haces un trato con el Cártel Zo que te otorga el derecho a llamarte miembro (durante una semana).\n\n Contrato de banda guerrera\n Solo puedes hacer un trato con un cártel por semana. Este efecto se comparte con toda la banda guerrera."}
MultiLanguageSpellData['es'][1249463] = {name = "[q3]Trato: Cártel Zo", additional_info = "Hechizo de 3.5 seg\nComponentes:\nPapiro nuevo , Instrumento forjado con maná , Tinta cálida (25)\nVándalos de la Forja de Maná\nRenombre:\n8\nUbicación:\nPunto Sombrío\n\n[q3]Trato: Cártel Zo\n[q2]Uso: Haces un trato con el Cártel Zo que te otorga el derecho a llamarte miembro (durante una semana).\n\n Contrato de banda guerrera\n Solo puedes hacer un trato con un cártel por semana. Este efecto se comparte con toda la banda guerrera.\nNecesitas ser de nivel 70\n[q]\"Un \"contrato\" a corto plazo redactado por escribas en el que se promete la fidelidad de una banda guerrera a un cártel de los Especuladores.\""}
MultiLanguageSpellData['es'][1249464] = {name = "Ayuda de Elune", additional_info = "Instante\n[q]Bestias, Supervivencia\nDaño de Bomba de fuego salvaje aumentado un 10%. Cuando Tormenta lunar se desvanece, obtienes la Ayuda de Elune, lo que hace que, durante 2 usos de Bomba de fuego salvaje, esta facultad inflija daño Arcano y su daño inicial aumente un 150%.\n\nPuntería\nDaño de Fuego rápido aumentado un 25%. Cuando Tormenta lunar se desvanece, obtienes la Ayuda de Elune, lo que hace que, durante 2 usos de Disparo de puntería, esta facultad inflija daño Arcano y su daño aumente un 10%."}
MultiLanguageSpellData['es'][1249465] = {name = "Trato: Cártel Ba", additional_info = "Instante\n[q]Haces un trato con el Cártel Ba que te otorga el derecho a llamarte miembro (durante una semana).\n\n Contrato de banda guerrera\n Solo puedes hacer un trato con un cártel por semana. Este efecto se comparte con toda la banda guerrera."}
