MultiLanguageSpellData['es'][1249651] = {name = "Favor de los reshii", additional_info = "Instante\n[q]Imbuye de más energía tu mantón reshii, lo que mejora su poder.\n\n Desbloquea el poder del mantón para adaptarse a tu especialización y te otorga Siega de los etéreos :\n\nExiste la posibilidad de que tus hechizos y facultades de ayuda concentren energías latentes a tu alrededor para infligir daño Arcano a dividir entre tu objetivo y los enemigos cercanos. Los enemigos con menos de un 35% de salud reciben un 20% más de daño."}
MultiLanguageSpellData['es'][1249658] = {name = "Aliento de Sindragosa", additional_info = "60 p. de poder rúnico\n{Instante} {1.5 min de reutilización}\n[q]Pides la asistencia en combate de Sindragosa durante 8 s, que inflige de forma continua [([139.788% of Attack Power]) * [(Poder de ataque * 0.98)][((Poder de ataque + [Offhand Attack Power]) * 2 / 3)] -- 2H, DW / Poder de ataque] p. de daño de Escarcha durante 1 s a los enemigos situados en un cono frente a ti. Al consumir Máquina de matar o Helada blanca, la duración aumenta 0.8 s. Inflige daño reducido a los objetivos secundarios.\n\nOtorga una carga de Potenciar arma de runas al inicio y 2 runas al final.\n(100ms de reutilización)"}
