MultiLanguageSpellData['es'][1250103] = {name = "Pilones de infusión", additional_info = "Rango ilimitado\nInstante\n[q]Los pilones Arcanos de la cámara suministran energía a Loom'ithar mediante haces Arcanos que activan una Nova de exceso cuando entran en contacto.\n\n Los jugadores que se interponen en el camino de los haces los bloquean y, al hacerlo, reciben 606071 p. de daño Arcano y una aplicación de Hiperinfusión cada 1 s. Este efecto se acumula."}
