MultiLanguageSpellData['es'][1250314] = {name = "Floración fantasmal", additional_info = "Alcance de 5 m\nHechizo de 2.5 seg\n[q]Las floraciones fantasmales son el vestigio energético de la flora de K'aresh y no se pueden incorporar a las recetas algarianas.\n\n Sin embargo, puedes intercambiarlas en el mercado de recursos por materiales algarianos. Su precio cambia cada día, así que deberás armarte de paciencia para conseguir las mejores ofertas."}
MultiLanguageSpellData['es'][1250317] = {name = "Floración fantasmal exuberante", additional_info = "Alcance de 5 m\nHechizo de 2.5 seg\n[q]Las floraciones fantasmales son el vestigio energético de la flora de K'aresh y no se pueden incorporar a las recetas algarianas.\n\n Sin embargo, puedes intercambiarlas en el mercado de recursos por materiales algarianos. Su precio cambia cada día, así que deberás armarte de paciencia para conseguir las mejores ofertas.\n\n Hay ejemplares de floración fantasmal que superan con creces su tamaño esperado. Esta, una de las pocas plantas que sobrevivieron al despiadado páramo de los desiertos de K'aresh, tenía la fama de crecer hasta alcanzar mayor tamaño en entornos frondosos de bosques de lo Indomable."}
MultiLanguageSpellData['es'][1250351] = {name = "Depósito desolado", additional_info = "Alcance de 5 m\nHechizo de 2.5 seg\n[q]Los mineros que buscan fortuna en K'aresh no encontrarán más que las escasas ofrendas de un mundo devastado. Si bien este mineral no es útil en la artesanía algariana, es posible que los habitantes de Tazavesh puedan sacar partido a estos escombros."}
MultiLanguageSpellData['es'][1250356] = {name = "Depósito desolado rico", additional_info = "Alcance de 5 m\nHechizo de 2.5 seg\n[q]Los mineros que buscan fortuna en K'aresh no encontrarán más que las escasas ofrendas de un mundo devastado. Si bien este mineral no es útil en la artesanía algariana, es posible que los habitantes de Tazavesh puedan sacar partido a estos escombros.\n\nA veces salen de debajo de la superficie depósitos más grandes de lo normal, para regocijo de mineros que buscan una buena fuente de ingresos."}
